const crypto = require('crypto');
function id(q) { return 'card-' + crypto.createHash('sha256').update(q.trim().toLowerCase()).digest('hex').slice(0,12); }
const cards = [];
function add(topicId, question, answer, explanation, difficulty, bloomLevel, tags) {
  cards.push({ id: id(question), question, answer, explanation, difficulty, bloomLevel, tags, topicId });
}

// fm-multimorbid (15)
add('fm-multimorbid','A 72-year-old man has HTN, T2DM, CKD stage 3, and osteoarthritis. He takes metformin, ramipril, amlodipine, and naproxen. Which medication should be stopped first?','Naproxen','NSAIDs worsen CKD, raise BP, increase CV risk, and antagonize antihypertensive agents. In multimorbid elderly patients, NSAIDs are high-priority deprescribing targets. Acetaminophen is preferred for OA pain.',4,'analyze',['multimorbidity','polypharmacy','NSAIDs','CKD','deprescribing']);
add('fm-multimorbid','What framework is most useful for prioritizing treatment goals in patients with multimorbidity?','Patient-centred goal-setting using shared decision-making','Guidelines designed for single diseases may conflict in multimorbid patients. Shared decision-making to identify the patient\'s priorities (e.g., functional independence vs. longevity) helps tailor care. The NICE multimorbidity guideline recommends this approach.',3,'apply',['multimorbidity','shared-decision-making','patient-centred']);
add('fm-multimorbid','Which validated tool helps identify potentially inappropriate medications in older adults with multimorbidity?','STOPP/START criteria (Screening Tool of Older Persons\' Prescriptions / Screening Tool to Alert to Right Treatment)','STOPP lists explicit criteria for medications to stop; START lists evidence-based medications to consider adding. They are more sensitive than the Beers Criteria for detecting drug-related hospital admissions in older Canadians.',3,'apply',['polypharmacy','STOPP-START','elderly','deprescribing']);
add('fm-multimorbid','A 68-year-old woman with heart failure (EF 35%), T2DM, and CKD stage 3b (eGFR 38) is started on an SGLT2 inhibitor. What additional benefit does this provide beyond glycemic control?','Reduction in HF hospitalizations and slowing of CKD progression','SGLT2 inhibitors (e.g., empagliflozin, dapagliflozin) reduce HF hospitalization and CV death in HFrEF and slow CKD progression independent of glycemic effect. They are now guideline-directed therapy for both HFrEF and CKD.',4,'analyze',['SGLT2i','heart-failure','CKD','multimorbidity','empagliflozin']);
add('fm-multimorbid','What is the primary goal of the "4Ms" framework used in age-friendly health systems for older adults with multimorbidity?','To focus care on What Matters, Medication, Mentation, and Mobility','The 4Ms framework (IHI/AHA) ensures care addresses patient priorities (What Matters), avoids harmful medications, manages cognitive/mood issues (Mentation), and maintains Mobility — all simultaneously across conditions.',2,'recall',['4Ms','age-friendly','multimorbidity','geriatrics']);
add('fm-multimorbid','A 75-year-old with COPD, depression, and T2DM has poor medication adherence. Which intervention most improves adherence in multimorbid patients?','Medication reconciliation plus simplified regimens (dose consolidation, pill organizers, blister packs)','Reducing pill burden, synchronizing refills, and using compliance aids significantly improve adherence. A pharmacist-led medication review is effective and recommended in Canadian practice.',3,'apply',['adherence','polypharmacy','multimorbidity','pharmacist']);
add('fm-multimorbid','Which condition is most commonly associated with multimorbidity as an "anchor" diagnosis in primary care?','Hypertension','HTN co-occurs with DM, CKD, CVD, stroke, and atrial fibrillation more than any other condition. It serves as the central node in most multimorbidity clusters seen in Canadian family practice.',2,'recall',['hypertension','multimorbidity','primary-care']);
add('fm-multimorbid','A 70-year-old man with AF, CKD stage 4 (eGFR 22), and HTN requires anticoagulation. Which agent is preferred?','Warfarin (vitamin K antagonist) with careful INR monitoring','DOACs (apixaban, rivaroxaban) are generally avoided when eGFR <15–25 mL/min due to renal elimination. Warfarin remains the anticoagulant of choice in advanced CKD with AF, though apixaban has emerging evidence down to eGFR 25.',4,'analyze',['anticoagulation','CKD','atrial-fibrillation','warfarin','DOAC']);
add('fm-multimorbid','What is "treatment burden" in the context of multimorbidity?','The effort required of patients to carry out recommended treatments across multiple conditions','Treatment burden includes pill-taking, monitoring, lifestyle modifications, appointments, and costs. High treatment burden is associated with non-adherence and poorer outcomes in multimorbid patients.',2,'recall',['treatment-burden','multimorbidity','patient-centred']);
add('fm-multimorbid','A 65-year-old woman with T2DM and CKD stage 3 develops hypertension. Which drug class is first-line for both nephroprotection and BP control?','ACE inhibitor or ARB','ACEi/ARBs reduce intraglomerular pressure and proteinuria in diabetic nephropathy. They are first-line for CKD with proteinuria per Hypertension Canada and Diabetes Canada guidelines.',2,'recall',['ACEi','ARB','CKD','nephroprotection','HTN']);
add('fm-multimorbid','Which mental health condition is most prevalent in patients with multimorbidity and significantly worsens outcomes?','Depression','Depression occurs in 20–30% of patients with two or more chronic conditions. It impairs self-management, medication adherence, and is independently associated with increased mortality in patients with CVD, DM, and COPD.',3,'apply',['depression','multimorbidity','mental-health']);
add('fm-multimorbid','What is the recommended approach to statin therapy in a frail 82-year-old with CVD, dementia, and limited life expectancy?','Consider deprescribing statins if the patient\'s life expectancy is short and QoL is the priority','Statins provide primary/secondary prevention over 3–5+ year horizons. In frail elderly with dementia and limited life expectancy, the harms (myopathy, interactions, pill burden) may outweigh benefits. Shared decision-making and goals of care should guide deprescribing.',4,'analyze',['statins','deprescribing','frailty','end-of-life','multimorbidity']);
add('fm-multimorbid','A 78-year-old with HF, CKD, and T2DM has hemoglobin of 95 g/L. What is the most likely cause?','Anemia of chronic kidney disease (renal anemia)','CKD causes decreased erythropoietin production. In patients with multimorbidity involving CKD, renal anemia is common. Check iron studies first; if iron replete, consider erythropoiesis-stimulating agents if eGFR <60 and Hb <100.',3,'apply',['anemia','CKD','erythropoietin','multimorbidity']);
add('fm-multimorbid','What is the role of a comprehensive geriatric assessment (CGA) in multimorbid older adults?','To evaluate functional status, cognition, mental health, nutrition, medications, and social support to create an integrated care plan','CGA identifies reversible contributors to functional decline, guides appropriate investigation intensity, and prioritizes interventions. It is recommended for frail older adults with multiple chronic conditions.',3,'apply',['CGA','geriatrics','frailty','multimorbidity']);
add('fm-multimorbid','A 73-year-old man with COPD, HF, and anxiety is prescribed a beta-blocker for HF. What is the appropriate approach given his COPD?','Use a cardioselective beta-blocker (e.g., bisoprolol, metoprolol succinate) — COPD is not an absolute contraindication','Cardioselective beta-blockers have minimal effect on beta-2 receptors at low doses. The mortality benefit of beta-blockers in HFrEF outweighs risk of mild COPD exacerbation. They should not be withheld in clinically stable COPD.',4,'analyze',['beta-blocker','COPD','HF','cardioselective','multimorbidity']);

// fm-geriatrics (15)
add('fm-geriatrics','What are the five domains of the FRAIL scale used to screen for frailty in older adults?','Fatigue, Resistance (stair climbing), Ambulation (walking), Illnesses (>5 comorbidities), Loss of weight (>5%)','The FRAIL scale is a validated, quick screening tool. Scores 0=robust, 1–2=pre-frail, 3–5=frail. It predicts falls, hospitalization, and mortality in community-dwelling older adults.',2,'recall',['frailty','FRAIL-scale','geriatrics','screening']);
add('fm-geriatrics','A 79-year-old woman falls at home. Which standardized test best assesses her dynamic balance and fall risk?','Timed Up and Go (TUG) test','TUG measures time to rise from a chair, walk 3 m, turn, and return. >12 seconds indicates fall risk. The Canadian Falls Prevention Curriculum recommends TUG for all community-dwelling older adults after a fall.',2,'recall',['falls','TUG','balance','geriatrics']);
add('fm-geriatrics','Which drug class is the most common pharmacological contributor to falls in older adults?','Psychotropics (benzodiazepines, antipsychotics, antidepressants)','Psychotropics cause sedation, orthostatic hypotension, and impaired coordination. Benzodiazepines double fall risk. Deprescribing is a priority in fall prevention per the AGS Beers Criteria and STOPP criteria.',3,'apply',['falls','benzodiazepines','psychotropics','deprescribing','geriatrics']);
add('fm-geriatrics','What Mini-Cog score suggests possible cognitive impairment requiring further evaluation?','Score of 0–2 out of 5 (0–3 recall words + clock drawing)','The Mini-Cog combines 3-word recall (1 point each) and clock drawing (0 or 2 points). A score ≤2 suggests possible dementia and warrants further evaluation with MoCA or formal neuropsychological testing.',2,'recall',['dementia','Mini-Cog','cognitive-screening','geriatrics']);
add('fm-geriatrics','An 80-year-old man is admitted post-hip fracture. On day 2 he becomes acutely confused, agitated, and disoriented. What is the diagnosis and key precipitant to address?','Delirium; address pain, urinary retention, constipation, medications, and infection','Delirium affects 14–56% of hospitalized older adults. Post-operative pain under-treatment is a key precipitant in hip fracture patients. Use the CAM tool to confirm. Non-pharmacological multicomponent prevention is first-line.',4,'analyze',['delirium','hip-fracture','geriatrics','CAM','hospitalization']);
add('fm-geriatrics','Which calcium and vitamin D daily doses are recommended for fracture prevention in adults over 70 years?','Calcium 1200 mg/day (dietary preferred) + Vitamin D 800–2000 IU/day','Osteoporosis Canada recommends 1200 mg calcium and at least 800 IU vitamin D daily for those ≥50 years, with up to 2000 IU/day in elderly or institutionalized individuals. Calcium supplements may modestly increase CV risk.',2,'recall',['osteoporosis','calcium','vitamin-D','fracture-prevention','geriatrics']);
add('fm-geriatrics','What is the DAST-10 used for in geriatric patients?','Screening for drug/substance use problems (Drug Abuse Screening Test — 10 items)','DAST-10 identifies problematic substance use including prescription opioids, benzodiazepines, and alcohol. Substance misuse is underdiagnosed in older adults and contributes to falls, delirium, and cognitive decline.',2,'recall',['substance-use','screening','DAST','geriatrics']);
add('fm-geriatrics','A 77-year-old woman with a recent hip fracture has a T-score of -2.7. She is on vitamin D and calcium. What pharmacological therapy should be started?','Bisphosphonate (e.g., alendronate or zoledronic acid)','Post-fracture patients with T-score ≤-2.5 meet criteria for pharmacological osteoporosis therapy. Zoledronic acid IV annually is effective post-hip fracture and reduces mortality. Alendronate 70 mg weekly is an oral option.',3,'apply',['osteoporosis','bisphosphonate','hip-fracture','T-score','zoledronic-acid']);
add('fm-geriatrics','What is the recommended screening interval for cognitive impairment in adults ≥65 in Canadian primary care?','Annual assessment using a validated tool (e.g., MoCA, Mini-Cog) in those with risk factors; no routine universal screening recommended by CTFPHC','The Canadian Task Force on Preventive Health Care (CTFPHC) does not recommend routine cognitive screening of asymptomatic adults. However, case-finding in those with memory complaints, vascular risk factors, or functional decline is appropriate.',3,'apply',['dementia','cognitive-screening','CTFPHC','geriatrics']);
add('fm-geriatrics','Which scale quantifies severity of functional impairment in activities of daily living (ADLs) in older adults?','Katz Index of ADLs (bathing, dressing, toileting, transferring, continence, feeding)','The Katz ADL Index scores 6 basic self-care functions. It is used to assess functional status, plan care transitions, and monitor disease progression. Lawton-Brody IADL scale assesses instrumental ADLs (cooking, finances, etc.).',2,'recall',['ADL','Katz-index','functional-status','geriatrics']);
add('fm-geriatrics','An 85-year-old nursing home resident is refusing meals and has lost 8% of body weight over 3 months. What is the first step in management?','Comprehensive assessment for reversible causes (dental problems, dysphagia, depression, medications, pain, constipation)','Malnutrition in older adults is often multifactorial. Reversible causes must be excluded before considering appetite stimulants or feeding tubes (which are rarely appropriate in advanced dementia). MNA (Mini Nutritional Assessment) can quantify risk.',3,'apply',['malnutrition','weight-loss','nursing-home','geriatrics','dysphagia']);
add('fm-geriatrics','Which antihypertensive target is recommended for community-dwelling adults ≥75 years according to Hypertension Canada?','SBP <130 mmHg if tolerated (based on SPRINT trial data)','SPRINT trial showed benefit of intensive BP control (SBP <120 target) in adults ≥75 without diabetes. Hypertension Canada recommends SBP <130 mmHg in high-CV-risk elderly patients if tolerated, with close monitoring for orthostatic hypotension.',4,'analyze',['hypertension','elderly','SBP-target','SPRINT','Hypertension-Canada']);
add('fm-geriatrics','What is urge urinary incontinence and what is first-line non-pharmacological management?','Involuntary urine leakage with sudden urge; first-line is bladder training and pelvic floor exercises','Urge incontinence (overactive bladder) is the most common type in elderly women. Bladder training (scheduled voiding, urge suppression) and pelvic floor physiotherapy are first-line before anticholinergics (which cause cognitive side effects in elderly).',3,'apply',['urinary-incontinence','overactive-bladder','pelvic-floor','geriatrics']);
add('fm-geriatrics','A 78-year-old man has a PMR (polymyalgia rheumatica) flare after prednisone taper. He also has osteoporosis. What bone protection should be prescribed?','Bisphosphonate (alendronate or zoledronic acid) plus calcium and vitamin D','Patients on glucocorticoids ≥7.5 mg/day for ≥3 months require bone protection. Osteoporosis Canada and ACR recommend bisphosphonate therapy with calcium/vitamin D supplementation to prevent glucocorticoid-induced osteoporosis.',3,'apply',['glucocorticoid-induced-osteoporosis','PMR','bisphosphonate','geriatrics']);
add('fm-geriatrics','What is advance care planning and when should it be initiated in older adults?','Ongoing process of discussing future healthcare goals, values, and preferences — ideally started early, before a health crisis','ACP includes identifying a substitute decision-maker, completing advance directives/personal directives, and discussing goals of care. Canadian guidelines recommend initiating ACP with all patients ≥65, especially those with life-limiting illness.',2,'recall',['advance-care-planning','goals-of-care','geriatrics','substitute-decision-maker']);

// rheum-ra (10)
add('rheum-ra','Which antibody is most specific for rheumatoid arthritis and predicts erosive disease?','Anti-cyclic citrullinated peptide antibody (anti-CCP / ACPA)','Anti-CCP has ~95% specificity for RA and is present in 60–70% of RA patients. It predicts erosive, destructive joint disease and may be positive years before symptom onset. RF has lower specificity.',2,'recall',['rheumatoid-arthritis','anti-CCP','serology','erosive-disease']);
add('rheum-ra','A 42-year-old woman presents with 8 weeks of symmetric swollen MCPs, PIPs, and wrists with >1 hour of morning stiffness. RF and anti-CCP are positive. What is the diagnosis and first-line DMARD?','Rheumatoid arthritis; methotrexate (MTX) is first-line DMARD','Early aggressive treatment with MTX prevents joint destruction. ACR/EULAR recommend starting MTX within 3 months of diagnosis. Folic acid supplementation reduces MTX toxicity. Target is remission or low disease activity.',3,'apply',['rheumatoid-arthritis','methotrexate','DMARD','early-treatment']);
add('rheum-ra','What blood tests should be monitored in a patient on methotrexate for RA?','CBC, LFTs, creatinine every 4–8 weeks initially, then every 3 months','MTX causes hepatotoxicity, myelosuppression, and nephrotoxicity. Alcohol use and other hepatotoxins increase risk. Monitoring guidelines: CBC + differential, AST/ALT, creatinine per ACR/CORA recommendations.',2,'recall',['methotrexate','monitoring','RA','hepatotoxicity','DMARD']);
add('rheum-ra','A patient with RA has failed methotrexate monotherapy after 3 months. Disease activity remains moderate. What is the next step per Canadian guidelines?','Add a biologic DMARD (e.g., TNF inhibitor) or targeted synthetic DMARD (e.g., JAK inhibitor) in combination with MTX','CORA (Canadian Rheumatology Association) guidelines recommend combination therapy when target (remission/low disease activity) is not achieved at 3 months. TNFi (etanercept, adalimumab) plus MTX is most evidence-based combination.',4,'analyze',['rheumatoid-arthritis','biologic','TNF-inhibitor','JAK-inhibitor','CORA']);
add('rheum-ra','What is the recommended screening before starting a TNF inhibitor for RA?','TB screening (TST or IGRA), hepatitis B serology, and updated vaccinations (especially live vaccines before starting biologics)','TNFi increase risk of reactivation TB and hepatitis B. All patients must be screened for latent TB (treat if positive before starting biologic) and hepatitis B (antiviral prophylaxis if HBsAg+). Live vaccines must be given before biologics.',3,'apply',['TNF-inhibitor','TB-screening','hepatitis-B','biologic','RA']);
add('rheum-ra','Which extra-articular manifestation of RA is the most common cause of premature death?','Cardiovascular disease (accelerated atherosclerosis)','RA is associated with a 1.5–2x increased CV risk independent of traditional risk factors. Systemic inflammation promotes atherosclerosis. Aggressive disease control and CV risk factor management are essential.',3,'apply',['rheumatoid-arthritis','cardiovascular','extra-articular','atherosclerosis']);
add('rheum-ra','What is Felty syndrome?','RA + splenomegaly + neutropenia (with recurrent infections)','Felty syndrome occurs in <1% of RA patients, usually with severe seropositive erosive disease. It increases risk of serious infections and lymphoma. Treatment includes aggressive RA control; G-CSF for severe neutropenia.',2,'recall',['Felty-syndrome','RA','splenomegaly','neutropenia']);
add('rheum-ra','A 55-year-old woman with RA on biologics develops a dry cough and dyspnea. CXR shows bilateral lower lobe ground-glass opacities. What should be considered?','Methotrexate pneumonitis or rheumatoid interstitial lung disease (ILD)','Both MTX (hypersensitivity pneumonitis) and RA-ILD can present this way. Discontinue MTX. HRCT chest and pulmonology referral are needed. RA-ILD (UIP pattern) may require antifibrotics (nintedanib) or immunosuppression.',4,'analyze',['RA','interstitial-lung-disease','methotrexate-pneumonitis','biologic']);
add('rheum-ra','Which DAS28 score indicates remission in rheumatoid arthritis?','DAS28 <2.6','The Disease Activity Score 28 (DAS28) uses tender/swollen joint counts, ESR or CRP, and patient global assessment. Scores: <2.6 = remission, 2.6–3.2 = low activity, 3.2–5.1 = moderate, >5.1 = high activity. Treat-to-target aims for DAS28 <2.6.',2,'recall',['DAS28','disease-activity','RA','remission','treat-to-target']);
add('rheum-ra','What is the leading cause of atlantoaxial subluxation in patients with long-standing RA?','Erosion of the transverse ligament and odontoid process by chronic synovitis of C1-C2 joint','Atlantoaxial instability (C1-C2) occurs in 30–40% of RA patients with long disease duration and can cause cervical myelopathy. Flexion-extension cervical X-rays screen for it. Pre-operative cervical spine assessment is essential before intubation.',3,'apply',['atlantoaxial-subluxation','RA','cervical-spine','cervical-myelopathy']);

// rheum-osteo (10)
add('rheum-osteo','What are the characteristic X-ray features of osteoarthritis in a hand joint?','Joint space narrowing, subchondral sclerosis, osteophytes (bone spurs), and subchondral cysts — no periarticular osteopenia','OA affects cartilage and subchondral bone without systemic inflammation. This contrasts with RA (periarticular osteopenia, uniform joint space loss, erosions) and gout (punched-out erosions with overhanging edges).',2,'recall',['osteoarthritis','X-ray','joint-space-narrowing','osteophytes']);
add('rheum-osteo','A 65-year-old woman has knee pain that worsens with activity and improves with rest. Examination shows bony enlargement, crepitus, and decreased ROM. What is the most appropriate initial therapy?','Exercise therapy (aerobic + strengthening) and weight loss for overweight patients','Exercise is the cornerstone of OA management per OARSI and Canadian guidelines. Strengthening the quadriceps reduces knee load. Weight loss of 10% significantly reduces knee OA symptoms. Topical NSAIDs are preferred over oral in elderly.',3,'apply',['osteoarthritis','knee','exercise','weight-loss','OARSI']);
add('rheum-osteo','Which joints are characteristically involved in primary nodal osteoarthritis?','DIP joints (Heberden nodes), PIP joints (Bouchard nodes), and CMC-1 (base of thumb)','Nodal OA is the most common form in women post-menopause. DIP and PIP bony enlargements (osteophytes) are characteristic. CMC-1 OA causes "square hand" deformity. These joints are typically spared in RA.',2,'recall',['osteoarthritis','Heberden-nodes','Bouchard-nodes','DIP','PIP']);
add('rheum-osteo','What is the preferred analgesic for osteoarthritis pain in elderly patients?','Acetaminophen up to 3–4 g/day (or 2 g/day in heavy alcohol users) as first-line; topical diclofenac as adjunct','Oral NSAIDs carry GI, renal, and CV risks in elderly. Topical NSAIDs (diclofenac gel) provide similar analgesia to oral NSAIDs with less systemic absorption. Opioids are third-line only for refractory OA not eligible for surgery.',3,'apply',['osteoarthritis','acetaminophen','topical-NSAID','elderly','analgesic']);
add('rheum-osteo','Intra-articular corticosteroid injection is used for knee OA. What is the maximum recommended frequency?','No more than 3–4 times per year in the same joint','Frequent intra-articular steroid injections accelerate cartilage loss. Short-term pain relief (2–8 weeks) is the goal. Patients with inflammatory flares (effusions, warmth) respond best. Hyaluronic acid injections have modest evidence.',2,'recall',['osteoarthritis','intra-articular-corticosteroid','knee','injection-frequency']);
add('rheum-osteo','What criteria indicate referral for total knee replacement (TKR)?','Moderate-severe OA with functional limitation, inadequate pain relief despite 3+ months of conservative therapy, and patient willing/fit for surgery','TKR improves pain and function in end-stage knee OA. Patient readiness and fitness (cardiac, metabolic optimization) are key. Average Canadian wait time exceeds 6 months; timely referral is essential.',3,'apply',['osteoarthritis','total-knee-replacement','surgical-referral','knee']);
add('rheum-osteo','Which risk factor most strongly predicts progression from normal to symptomatic knee OA?','Obesity (BMI >30)','Each unit increase in BMI increases knee OA risk significantly. Adipose tissue secretes pro-inflammatory adipokines (leptin, adiponectin) that directly affect cartilage. Weight loss is the only intervention shown to slow radiographic OA progression.',3,'apply',['osteoarthritis','obesity','risk-factor','BMI','progression']);
add('rheum-osteo','What is calcium pyrophosphate deposition (CPPD) disease and how does it present acutely?','Crystal arthropathy caused by calcium pyrophosphate crystals; acute CPPD (pseudogout) presents as acute mono-/oligoarthritis most commonly in the knee with chondrocalcinosis on X-ray','CPPD/pseudogout is often triggered by illness or surgery. Synovial fluid shows positively birefringent (weakly) rhomboid-shaped crystals under polarized microscopy. Treatment: NSAIDs, colchicine, or intra-articular steroids.',3,'apply',['CPPD','pseudogout','chondrocalcinosis','crystal-arthropathy','knee']);
add('rheum-osteo','What is the role of glucosamine/chondroitin supplements in OA management per Canadian guidelines?','Not routinely recommended — evidence for pain relief and structural benefit is insufficient','OARSI 2019 guidelines: glucosamine/chondroitin are not recommended due to inconsistent evidence. Some patients report symptomatic benefit. They are safe but should not replace evidence-based therapies.',2,'recall',['osteoarthritis','glucosamine','chondroitin','supplement','evidence']);
add('rheum-osteo','A 70-year-old woman with known knee OA presents with a large, tense knee effusion after a fall. Aspiration reveals turbid fluid with 40,000 WBC and positive Gram stain. What is the diagnosis?','Septic arthritis (bacterial joint infection) — not OA flare','Septic arthritis requires urgent joint drainage and IV antibiotics. S. aureus is the most common organism. High WBC (>50,000 strongly suggests infection), positive Gram stain, or positive culture confirms diagnosis. Treat as emergency.',4,'analyze',['septic-arthritis','knee-effusion','WBC','Gram-stain','emergency']);

// rheum-lupus (7)
add('rheum-lupus','A 28-year-old woman presents with a malar rash, arthritis, proteinuria, and a positive ANA (1:320). Which antibody is most specific for SLE?','Anti-dsDNA (anti-double-stranded DNA antibody)','Anti-dsDNA has ~95% specificity for SLE and correlates with disease activity and lupus nephritis. Anti-Sm is also highly specific but less sensitive. ANA is sensitive (>95%) but not specific.',2,'recall',['SLE','anti-dsDNA','ANA','antibody','lupus']);
add('rheum-lupus','Which organ involvement in SLE most significantly impacts long-term prognosis?','Lupus nephritis (renal involvement)','Lupus nephritis occurs in 50% of SLE patients and is a major cause of morbidity and mortality. Class III/IV proliferative nephritis requires aggressive immunosuppression (hydroxychloroquine + mycophenolate or cyclophosphamide + high-dose steroids).',3,'apply',['lupus-nephritis','SLE','prognosis','immunosuppression']);
add('rheum-lupus','What is the mechanism of antiphospholipid syndrome (APS) complicating SLE?','Antiphospholipid antibodies (lupus anticoagulant, anti-cardiolipin, anti-β2GP1) cause hypercoagulability leading to arterial/venous thrombosis and pregnancy loss','APS in SLE increases risk of DVT, stroke, and recurrent miscarriage. Diagnosis requires a clinical event plus persistent positive antibody test >12 weeks apart. Treatment: long-term anticoagulation with warfarin.',3,'apply',['antiphospholipid-syndrome','SLE','thrombosis','lupus-anticoagulant','warfarin']);
add('rheum-lupus','Which drug is recommended for all patients with SLE regardless of disease severity?','Hydroxychloroquine (HCQ)','HCQ reduces SLE flares, organ damage accrual, thrombosis risk, and improves pregnancy outcomes. It is recommended indefinitely for all SLE patients. Annual ophthalmology screening for retinopathy is required.',2,'recall',['SLE','hydroxychloroquine','HCQ','retinopathy','treatment']);
add('rheum-lupus','A 25-year-old woman with SLE is planning pregnancy. Which antibody predicts risk of neonatal lupus and congenital heart block?','Anti-Ro/SSA (and anti-La/SSB) antibodies','Anti-Ro antibodies cross the placenta and can cause neonatal lupus (transient rash, cytopenias) and congenital complete heart block (irreversible). Fetal cardiac monitoring by echocardiography is recommended from 16–28 weeks in anti-Ro+ mothers.',3,'apply',['SLE','pregnancy','anti-Ro','neonatal-lupus','congenital-heart-block']);
add('rheum-lupus','What are the SLEDAI criteria used for?','Scoring SLE disease activity (SLE Disease Activity Index)','SLEDAI assesses 24 clinical and laboratory features across 9 organ systems. Scores >4 indicate active disease requiring treatment adjustment. It is used in clinical care and research to monitor disease activity over time.',2,'recall',['SLE','SLEDAI','disease-activity','monitoring']);
add('rheum-lupus','A patient with SLE develops a butterfly rash flare 3 days after starting trimethoprim-sulfamethoxazole for a UTI. What phenomenon is this?','Drug-induced lupus or SLE flare triggered by sulfonamide antibiotic','Sulfonamides, procainamide, hydralazine, and minocycline can trigger drug-induced lupus or exacerbate SLE. Nitrofurantoin or cephalosporins are safer UTI treatment options in SLE patients.',3,'apply',['SLE','drug-induced-lupus','sulfonamide','flare','medication-safety']);

// derm-common (10)
add('derm-common','A 35-year-old woman has an intensely pruritic, erythematous rash with vesicles on flexor surfaces and neck after starting a new laundry detergent. What is the diagnosis?','Allergic contact dermatitis (ACD)','ACD is a type IV delayed hypersensitivity reaction. The distribution corresponds to contact area. Patch testing identifies the allergen. Treatment: remove trigger, topical corticosteroids, antihistamines for itch.',3,'apply',['contact-dermatitis','allergic','type-IV-hypersensitivity','patch-testing']);
add('derm-common','What are the ABCDE criteria used for in dermatology?','Screening pigmented lesions for malignant melanoma: Asymmetry, Border irregularity, Color variation, Diameter >6mm, Evolution (change over time)','The ABCDE mnemonic is a clinical screening tool. Any single criterion or "ugly duckling" sign (lesion that looks different from others) warrants dermatology referral. Dermoscopy increases diagnostic accuracy.',2,'recall',['melanoma','ABCDE','pigmented-lesion','screening','dermoscopy']);
add('derm-common','A 22-year-old man has comedones, inflammatory papules, and nodules on the face and back. What is first-line treatment for moderate inflammatory acne?','Topical benzoyl peroxide + topical retinoid (e.g., adapalene); oral doxycycline if inadequate response','Combination topical therapy (retinoid + benzoyl peroxide) is most effective for inflammatory acne. Oral antibiotics are added for moderate-severe disease. Isotretinoin is reserved for nodular/cystic acne or antibiotic-resistant moderate acne.',3,'apply',['acne','benzoyl-peroxide','retinoid','doxycycline','treatment']);
add('derm-common','What is the pathognomonic skin finding of psoriasis?','Auspitz sign (pinpoint bleeding when scale is removed from plaque) and Koebner phenomenon (lesions develop at trauma sites)','Psoriasis presents as well-demarcated erythematous plaques with silvery scale on extensor surfaces, scalp, and nails. Nail pitting and onycholysis also occur. About 30% develop psoriatic arthritis.',2,'recall',['psoriasis','Auspitz-sign','Koebner-phenomenon','plaque','nail-pitting']);
add('derm-common','A 6-month-old infant has oozing, crusted erythematous patches on cheeks and scalp with intense itch. What is the diagnosis?','Atopic dermatitis (infantile eczema)','Atopic dermatitis affects 20% of children. Infantile pattern: face, scalp, and extensor surfaces. Treatment: emollients (moisturizers) as cornerstone, topical corticosteroids for flares, avoidance of triggers. Often improves by school age.',2,'recall',['atopic-dermatitis','eczema','infantile','emollient','topical-corticosteroid']);
add('derm-common','What is the first-line treatment for tinea corporis (ringworm)?','Topical antifungal (e.g., clotrimazole, terbinafine) for 2–4 weeks','Tinea corporis is caused by dermatophytes. Diagnosis is confirmed by KOH preparation showing hyphae. Topical terbinafine is more effective than azoles. Oral antifungals (terbinafine, itraconazole) are used for extensive, tinea capitis, or nail involvement.',2,'recall',['tinea-corporis','ringworm','antifungal','clotrimazole','terbinafine']);
add('derm-common','A 65-year-old man presents with a pearly nodule with rolled edges and telangiectasia on his nose. He is a farmer with extensive sun exposure. What is the most likely diagnosis?','Basal cell carcinoma (BCC)','BCC is the most common skin cancer. Nodular BCC has classic pearly rolled border with telangiectasia. It rarely metastasizes but causes local tissue destruction. Treatment: surgical excision or Mohs micrographic surgery.',2,'recall',['basal-cell-carcinoma','BCC','sun-exposure','nodular','treatment']);
add('derm-common','What is the first-line treatment for mild-to-moderate plaque psoriasis?','Topical corticosteroids (moderate-to-high potency) combined with topical vitamin D analogues (calcipotriol)','The calcipotriol/betamethasone combination (Dovobet) is the most effective topical treatment for plaque psoriasis. It reduces scale and erythema with fewer steroid side effects than monotherapy. Phototherapy and biologics are used for moderate-severe disease.',3,'apply',['psoriasis','topical-corticosteroid','calcipotriol','Dovobet','treatment']);
add('derm-common','Which condition presents as silvery-white lacy patches on the buccal mucosa that are asymptomatic and require no treatment?','Lichen planus (reticular pattern — Wickham striae)','Oral lichen planus is a chronic inflammatory condition. Reticular (white lacy) pattern is benign. Erosive pattern causes pain and has slight malignant potential. Diagnosis: biopsy. Treatment of erosive type: topical or systemic corticosteroids.',3,'apply',['lichen-planus','Wickham-striae','oral-mucosa','biopsy']);
add('derm-common','A 55-year-old woman develops a painful, burning vesicular rash in a dermatomal distribution on her left thorax. What is the treatment?','Antiviral therapy: valacyclovir 1000 mg TID × 7 days, initiated within 72 hours of rash onset','Herpes zoster (shingles) reactivation of VZV. Antivirals reduce duration and severity, and prevent post-herpetic neuralgia (PHN). Adjunctive gabapentin or amitriptyline treats neuropathic pain. Shingrix (recombinant zoster vaccine) prevents recurrence.',3,'apply',['herpes-zoster','shingles','valacyclovir','postherpetic-neuralgia','Shingrix']);

// derm-cancer (10)
add('derm-cancer','What is the most important prognostic factor for cutaneous melanoma?','Breslow thickness (depth of invasion in mm)','Breslow thickness is the single most important prognostic factor, determining T stage in AJCC staging. Tumors <0.8 mm have >95% 5-year survival; >4 mm have <50%. Clark level and ulceration are also prognostic.',2,'recall',['melanoma','Breslow-thickness','prognosis','AJCC-staging']);
add('derm-cancer','A 72-year-old farmer has a 1.5 cm scaly, indurated lesion on his lower lip with central ulceration. What is the most likely diagnosis?','Squamous cell carcinoma (SCC)','SCC on the lip has higher metastatic potential than SCC at other sites. Risk factors: UV, chronic inflammation, HPV, tobacco. Sentinel node biopsy may be considered for high-risk lesions. Wide local excision is treatment of choice.',3,'apply',['squamous-cell-carcinoma','SCC','lip','metastasis','UV-exposure']);
add('derm-cancer','What is the recommended surgical margin for a primary melanoma with Breslow thickness 1.01–2.0 mm?','1 cm margin','AJCC and Canadian guidelines: <1 mm Breslow → 1 cm margin; 1–2 mm → 1 cm (some guidelines 1–2 cm); >2 mm → 2 cm; >4 mm → 2 cm. Sentinel lymph node biopsy is offered for tumors ≥0.8 mm.',3,'apply',['melanoma','surgical-margin','Breslow','sentinel-node','excision']);
add('derm-cancer','Which virus is strongly associated with Merkel cell carcinoma (MCC)?','Merkel cell polyomavirus (MCV)','MCV is present in ~80% of MCC cases and promotes tumorigenesis. MCC is a rare but aggressive neuroendocrine skin cancer occurring in elderly, immunocompromised patients. Treatment: wide excision + sentinel lymph node biopsy + adjuvant radiotherapy.',2,'recall',['Merkel-cell-carcinoma','MCV','polyomavirus','neuroendocrine','skin-cancer']);
add('derm-cancer','What is actinic keratosis and why is it clinically significant?','Precancerous UV-induced keratotic lesion with risk of progression to SCC (1–10% per year)','AK (solar keratosis) appears as rough, scaly patches on sun-damaged skin. Treatment: cryotherapy, topical 5-FU, imiquimod, or diclofenac gel. Multiple AKs indicate field cancerization and high future SCC risk.',3,'apply',['actinic-keratosis','SCC','precancerous','cryotherapy','5-FU']);
add('derm-cancer','What is the recommended follow-up interval after excision of a stage IB melanoma?','Clinical exam every 3–6 months for 3 years, then annually','Stage I-II melanoma has risk of local recurrence and systemic metastasis. Skin and lymph node examination is recommended. Routine imaging (CT, PET) is not recommended for stage I unless symptomatic.',2,'recall',['melanoma','follow-up','staging','surveillance']);
add('derm-cancer','A patient presents with multiple BCCs, jaw cysts, and calcification of the falx cerebri. What is the diagnosis?','Nevoid basal cell carcinoma syndrome (Gorlin syndrome) — PTCH1 mutation','Gorlin syndrome is an autosomal dominant condition with multiple BCCs starting at a young age, odontogenic keratocysts, bifid ribs, and calcified falx cerebri. Avoid radiotherapy as it triggers additional BCCs. Vismodegib (hedgehog pathway inhibitor) is used for extensive disease.',3,'apply',['Gorlin-syndrome','BCC','PTCH1','hedgehog-pathway','vismodegib']);
add('derm-cancer','What is the first-line immunotherapy for unresectable or metastatic melanoma?','Pembrolizumab or nivolumab (anti-PD-1 checkpoint inhibitors)','Anti-PD-1 agents have revolutionized melanoma treatment, achieving durable responses in ~40% of patients. BRAF V600E-mutant melanoma can also receive BRAF+MEK inhibitors (dabrafenib+trametinib). Combination ipilimumab+nivolumab offers higher response rates with more toxicity.',3,'apply',['melanoma','immunotherapy','pembrolizumab','nivolumab','checkpoint-inhibitor']);
add('derm-cancer','Which skin cancer has the highest metastatic potential among common skin cancers?','Merkel cell carcinoma (higher than SCC; much higher than BCC)','Among common skin cancers: MCC >SCC >BCC for metastatic potential. However, melanoma is the most lethal overall. High-risk SCC features: >2 cm, deep invasion, perineural invasion, immunosuppression, ear/lip location.',2,'recall',['Merkel-cell','SCC','BCC','metastasis','skin-cancer']);
add('derm-cancer','What is the indication for sentinel lymph node biopsy (SLNB) in melanoma?','Breslow thickness ≥0.8 mm (or ≥0.75 mm with ulceration or mitoses) — T1b and above','SLNB provides staging information and guides adjuvant therapy decisions. Positive SLNB may warrant adjuvant immunotherapy (pembrolizumab) or targeted therapy. It does not improve survival in node-negative patients but identifies those at higher risk.',3,'apply',['melanoma','sentinel-node-biopsy','SLNB','staging','adjuvant-therapy']);

// hem-anemia (15)
add('hem-anemia','What is the MCV cut-off that distinguishes microcytic from normocytic anemia?','MCV <80 fL = microcytic; 80–100 fL = normocytic; >100 fL = macrocytic','MCV-based classification narrows the differential: microcytic (iron deficiency, thalassemia, sideroblastic, ACD in chronic inflammation); normocytic (acute blood loss, hemolysis, ACD, aplastic anemia); macrocytic (B12/folate deficiency, hypothyroidism, alcohol, medications).',1,'recall',['anemia','MCV','microcytic','normocytic','macrocytic']);
add('hem-anemia','A 30-year-old vegetarian woman has Hb 88 g/L, MCV 72 fL, low serum ferritin (8 µg/L), and low transferrin saturation. What is the diagnosis and first-line treatment?','Iron deficiency anemia; treat with oral ferrous sulfate 325 mg (elemental iron ~65 mg) TID between meals','IDA is the most common nutritional anemia globally. Ferritin <15 µg/L confirms iron deficiency. Oral iron is first-line; IV iron (ferric carboxymaltose) for intolerance or malabsorption. Treat underlying cause (menorrhagia, GI blood loss).',2,'recall',['iron-deficiency-anemia','ferritin','ferrous-sulfate','IV-iron']);
add('hem-anemia','What distinguishes thalassemia trait from iron deficiency anemia on CBC?','Thalassemia trait: low MCV with normal/high RBC count and normal ferritin; iron deficiency: low MCV with low ferritin and low RBC','Mentzer index (<13 suggests thalassemia, >13 suggests IDA). Thalassemia trait is confirmed by Hb electrophoresis (elevated HbA2 >3.5% in beta-thalassemia trait). Iron supplementation does not help thalassemia trait.',3,'apply',['thalassemia','iron-deficiency','Mentzer-index','Hb-electrophoresis','MCV']);
add('hem-anemia','A 65-year-old woman has Hb 92 g/L, MCV 110 fL, hypersegmented neutrophils, and low serum B12. What is the most likely underlying cause?','B12 deficiency from pernicious anemia or dietary insufficiency (veganism)','Macrocytic megaloblastic anemia with hypersegmented neutrophils (>5 lobes, or any 6-lobed PMN) is characteristic of B12 or folate deficiency. Anti-intrinsic factor antibodies confirm pernicious anemia. Treat with IM B12 (cyanocobalamin) or high-dose oral B12.',3,'apply',['macrocytic-anemia','B12-deficiency','pernicious-anemia','hypersegmented-neutrophils','cyanocobalamin']);
add('hem-anemia','What is anemia of chronic disease (ACD) and which test best distinguishes it from IDA?','ACD is caused by inflammatory cytokines reducing EPO and iron utilization; ferritin is normal or elevated in ACD (vs. low in IDA)','In ACD, hepcidin (acute-phase reactant) sequesters iron in macrophages. Ferritin is an acute-phase reactant — elevated in inflammation even with depleted stores. Serum transferrin receptor (sTfR) is elevated in IDA but normal in ACD. sTfR/log ferritin ratio distinguishes them.',3,'apply',['anemia-of-chronic-disease','ACD','ferritin','transferrin-receptor','hepcidin']);
add('hem-anemia','A 45-year-old man with sickle cell disease presents with sudden-onset pallor, Hb drops from 85 to 55 g/L, reticulocyte count near zero, and fever. What is the diagnosis?','Aplastic crisis due to Parvovirus B19 infection','Parvovirus B19 infects erythroid precursors, halting RBC production. In patients with hemolytic anemias (SCD, thalassemia, spherocytosis), rapid Hb drop occurs. Reticulocytopenia is key. Treatment: supportive (transfusion); parvovirus infection is self-limited.',4,'analyze',['sickle-cell','aplastic-crisis','parvovirus-B19','reticulocytopenia','hemolytic-anemia']);
add('hem-anemia','What is the direct antiglobulin test (DAT / Coombs test) used to detect?','IgG or complement (C3d) coating the surface of red blood cells, indicating immune-mediated hemolysis','Positive DAT indicates warm (IgG) or cold (IgM/complement) autoimmune hemolytic anemia, drug-induced hemolysis, or hemolytic transfusion reaction. Warm AIHA: treat with steroids ± rituximab. Cold agglutinin disease: avoid cold, treat underlying cause.',2,'recall',['DAT','Coombs-test','AIHA','autoimmune-hemolytic-anemia','hemolysis']);
add('hem-anemia','A 55-year-old woman on methyldopa develops anemia with positive DAT, elevated indirect bilirubin, and low haptoglobin. What is the diagnosis?','Drug-induced immune hemolytic anemia (DIIHA) due to methyldopa','Methyldopa (and other drugs: penicillin, cephalosporins, NSAIDs, quinine) causes DIIHA via drug-hapten, immune complex, or autoantibody mechanisms. Discontinue offending drug; hemolysis usually resolves in days to weeks.',3,'apply',['drug-induced-hemolytic-anemia','methyldopa','DAT','haptoglobin','DIIHA']);
add('hem-anemia','What is the hallmark peripheral blood finding of microangiopathic hemolytic anemia (MAHA)?','Schistocytes (fragmented RBCs) on blood film','MAHA occurs in TTP, HUS, DIC, and malignant hypertension. Schistocytes result from mechanical shearing of RBCs at fibrin strands. Combined with thrombocytopenia, elevated LDH, low haptoglobin, and elevated indirect bilirubin.',2,'recall',['MAHA','schistocytes','TTP','HUS','DIC']);
add('hem-anemia','What is hereditary spherocytosis and what is its most common complication?','Autosomal dominant defect in RBC membrane proteins (ankyrin, spectrin, band 3) causing spherical, osmotically fragile RBCs; most common complication is pigment gallstones (bilirubin cholelithiasis)','HS presents with hemolytic anemia, splenomegaly, and jaundice. Osmotic fragility test and EMA binding test confirm diagnosis. Splenectomy reduces hemolysis but increases infection risk (pneumococcal vaccines mandatory).',3,'apply',['hereditary-spherocytosis','splenomegaly','gallstones','splenectomy','osmotic-fragility']);
add('hem-anemia','What is the treatment for aplastic anemia in a 25-year-old with a compatible sibling donor?','Allogeneic hematopoietic stem cell transplant (HSCT) from matched sibling — curative','Severe aplastic anemia (SAA): pancytopenia with hypocellular marrow. Young patients with matched sibling should proceed to HSCT. Older patients or no donor: immunosuppression with anti-thymocyte globulin (ATG) + cyclosporine + eltrombopag.',3,'apply',['aplastic-anemia','HSCT','immunosuppression','ATG','eltrombopag']);
add('hem-anemia','What is the threshold for red blood cell transfusion in a hemodynamically stable hospitalized adult without cardiac disease?','Hb <70 g/L (restrictive transfusion strategy)','TRICC trial and Canadian Blood Services guidelines support restrictive transfusion (Hb <70 g/L) in stable patients. Liberal transfusion (Hb <100 g/L) threshold is used in acute MI, ACS, and post-cardiac surgery. Each unit raises Hb by ~10 g/L.',2,'recall',['RBC-transfusion','transfusion-threshold','restrictive','TRICC','hemoglobin']);
add('hem-anemia','A 70-year-old man with CKD stage 4 has Hb 88 g/L, reticulocyte count 0.5%, and ferritin 450 µg/L. What is the likely cause of his anemia?','Renal anemia (anemia of CKD) due to decreased erythropoietin production','EPO deficiency in CKD causes normocytic, normochromic anemia with low reticulocyte count. Iron studies: ferritin often elevated due to inflammation. IV iron may be needed if TSAT <20%. If iron replete, ESA (darbepoetin, epoetin alfa) is indicated when Hb <100 g/L.',3,'apply',['renal-anemia','CKD','erythropoietin','ESA','darbepoetin']);
add('hem-anemia','What is the normal range for hemoglobin and what defines anemia in adult females?','Normal Hb in adult women: 120–160 g/L; anemia defined as Hb <120 g/L (WHO) or <115 g/L (some guidelines)','WHO defines anemia as Hb <120 g/L in non-pregnant women, <130 g/L in men, <110 g/L in pregnant women. Canadian Blood Services uses similar thresholds. Severity: mild 100–119 g/L, moderate 70–99 g/L, severe <70 g/L.',1,'recall',['hemoglobin','anemia','WHO-definition','normal-range']);
add('hem-anemia','A 35-year-old woman from Southeast Asia has Hb 98 g/L, MCV 64 fL, normal ferritin, and HbA2 5.8% on electrophoresis. What is the diagnosis?','Beta-thalassemia trait (carrier state)','HbA2 >3.5% confirms beta-thalassemia trait. These patients have mild microcytic anemia and should not receive unnecessary iron supplementation. Genetic counseling is important if partner is also a carrier (risk of beta-thalassemia major in offspring).',3,'apply',['beta-thalassemia','HbA2','Hb-electrophoresis','microcytic','genetic-counseling']);

// hem-coag (15)
add('hem-coag','A 6-year-old boy has recurrent hemarthroses and deep muscle bleeds. PTT is prolonged, PT is normal, and platelet count is normal. What is the diagnosis?','Hemophilia A (factor VIII deficiency)','Hemophilia A is X-linked recessive. Prolonged PTT with normal PT indicates intrinsic pathway defect (factors VIII, IX, XI, XII). Hemophilia A (factor VIII) is 4x more common than B (factor IX). Diagnosis confirmed by factor assay.',2,'recall',['hemophilia-A','factor-VIII','hemarthrosis','PTT','X-linked']);
add('hem-coag','What is von Willebrand disease type 1 and what is first-line treatment for minor bleeding?','Partial quantitative deficiency of vWF; first-line is desmopressin (DDAVP) IV/SC/intranasal','DDAVP stimulates endothelial release of stored vWF and factor VIII. Effective for vWD type 1 and mild hemophilia A. Not effective for types 2B (may cause thrombocytopenia) or type 3. vWF concentrate used for major bleeding.',3,'apply',['von-Willebrand-disease','DDAVP','desmopressin','vWF','bleeding']);
add('hem-coag','What is the mechanism of disseminated intravascular coagulation (DIC)?','Systemic activation of coagulation by circulating triggers (e.g., sepsis, trauma, malignancy), leading to consumption of clotting factors and platelets, causing simultaneous bleeding and microvascular thrombosis','DIC laboratory: low platelets, low fibrinogen, elevated PT/PTT, elevated D-dimer/FDPs, and schistocytes. Treat the underlying cause. Transfuse FFP/cryoprecipitate for active bleeding. Low-dose hepcidin for thrombotic-predominant DIC (controversial).',3,'apply',['DIC','disseminated-intravascular-coagulation','sepsis','coagulopathy','fibrinogen']);
add('hem-coag','A 55-year-old woman on warfarin for AF has an INR of 9.2 but no active bleeding. What is the management?','Hold warfarin and give low-dose oral vitamin K (1–2.5 mg)','For INR >8 without bleeding: hold warfarin + give oral vitamin K 1–2.5 mg (not IV, which causes erratic correction). For major/life-threatening bleeding with supratherapeutic INR: 4-factor PCC (prothrombin complex concentrate) + IV vitamin K 10 mg.',3,'apply',['warfarin','supratherapeutic-INR','vitamin-K','PCC','anticoagulation']);
add('hem-coag','What is the antidote for dabigatran (direct thrombin inhibitor) in life-threatening bleeding?','Idarucizumab (Praxbind) — humanized monoclonal antibody fragment that binds and neutralizes dabigatran','Idarucizumab (5 g IV) reverses dabigatran within minutes. For factor Xa inhibitors (apixaban, rivaroxaban): andexanet alfa (Ondexxya) or 4-factor PCC if andexanet unavailable. Dialysis can remove dabigatran (small volume of distribution).',3,'apply',['dabigatran','idarucizumab','reversal','anticoagulation','bleeding']);
add('hem-coag','Heparin-induced thrombocytopenia (HIT) — what is the pathophysiology and when does it typically occur?','Immune-mediated: IgG antibodies against PF4-heparin complex activate platelets, causing thrombocytopenia and thrombosis; typically occurs 4–14 days after heparin exposure','HIT is paradoxically prothrombotic. Key: platelet count falls >50% or to <100, with new thrombosis. 4T score assesses probability. Immediately stop all heparin and start non-heparin anticoagulation (argatroban, bivalirudin, fondaparinux, or DOAC).',4,'analyze',['HIT','heparin-induced-thrombocytopenia','PF4','4T-score','argatroban']);
add('hem-coag','What thrombophilia is most commonly associated with venous thromboembolism in Canada?','Factor V Leiden mutation (resistance to activated protein C)','Factor V Leiden is the most common inherited thrombophilia (5% prevalence in Caucasians). Heterozygotes have 3–5x increased VTE risk; homozygotes 50–100x. Does not generally require long-term anticoagulation unless recurrent or unprovoked VTE.',2,'recall',['Factor-V-Leiden','thrombophilia','VTE','APC-resistance','hereditary']);
add('hem-coag','What is the appropriate duration of anticoagulation for a first unprovoked proximal DVT?','Minimum 3 months with reassessment for extended therapy based on bleeding risk and patient preference','Canadian guidelines (Thrombosis Canada): 3 months for provoked VTE; extended anticoagulation (indefinite) for unprovoked proximal DVT if low-moderate bleeding risk. DOACs (rivaroxaban, apixaban) are preferred. Use PADUA, HASBLED scores to guide decision.',3,'apply',['DVT','anticoagulation-duration','DOAC','unprovoked-VTE','Thrombosis-Canada']);
add('hem-coag','What is the treatment of choice for immune thrombocytopenic purpura (ITP) with platelet count <20 × 10⁹/L?','Corticosteroids (prednisone 1 mg/kg/day) ± IVIG for faster response in bleeding or pre-procedure','ITP is autoimmune destruction of platelets by anti-GPIIb/IIIa or anti-GPIb/IX antibodies. Corticosteroids are first-line. IVIG provides faster platelet increase (used before surgery or in active bleeding). Rituximab and thrombopoietin receptor agonists (eltrombopag) for refractory ITP.',3,'apply',['ITP','thrombocytopenia','prednisone','IVIG','splenectomy']);
add('hem-coag','A 35-year-old pregnant woman develops microangiopathic hemolytic anemia, thrombocytopenia, and acute renal failure in her first trimester. What is the most likely diagnosis?','Thrombotic thrombocytopenic purpura (TTP) — ADAMTS13 deficiency','TTP pentad: MAHA + thrombocytopenia + neurological symptoms + renal failure + fever. ADAMTS13 activity <10% confirms congenital or immune TTP. Treatment: emergent plasma exchange (PEX) + caplacizumab + steroids. Without treatment, 90% mortality.',4,'analyze',['TTP','ADAMTS13','plasma-exchange','MAHA','caplacizumab']);
add('hem-coag','What is the mechanism of action of clopidogrel and when is dual antiplatelet therapy (DAPT) indicated?','Clopidogrel irreversibly inhibits P2Y12 ADP receptor on platelets; DAPT (ASA + clopidogrel) is indicated for 12 months post-ACS or PCI with stent placement','Clopidogrel is a prodrug requiring CYP2C19 activation. Ticagrelor and prasugrel are more potent and reliable P2Y12 inhibitors. CYP2C19 poor metabolizers on clopidogrel have higher MACE rates. DAPT duration depends on stent type and bleeding risk.',3,'apply',['clopidogrel','P2Y12','DAPT','ACS','PCI']);
add('hem-coag','What is the normal platelet count range and at what level does spontaneous bleeding risk increase significantly?','Normal: 150–400 × 10⁹/L; spontaneous bleeding risk increases significantly below 10–20 × 10⁹/L','Platelet thresholds for procedures: >50 × 10⁹/L for major surgery, >80 × 10⁹/L for neuraxial anesthesia, >100 × 10⁹/L for neurosurgery. Spontaneous intracranial bleeding risk increases below 10 × 10⁹/L.',2,'recall',['platelets','thrombocytopenia','bleeding-risk','transfusion-threshold']);
add('hem-coag','A 60-year-old man has a persistently elevated PT and aPTT, and a mixing study corrects both. What does this suggest?','Factor deficiency (correction with mixing study = factor deficiency; failure to correct = inhibitor/lupus anticoagulant)','Mixing study: 1:1 mix of patient plasma with normal plasma. Correction suggests factor deficiency (e.g., liver disease, warfarin, factor deficiency). Non-correction (incubated) suggests factor inhibitor (e.g., acquired hemophilia A) or lupus anticoagulant.',3,'apply',['mixing-study','coagulopathy','factor-deficiency','inhibitor','lupus-anticoagulant']);
add('hem-coag','What is the primary hemostatic defect in Bernard-Soulier syndrome?','Deficiency or dysfunction of GPIb-IX-V complex — the platelet receptor for von Willebrand factor','Bernard-Soulier syndrome is a rare autosomal recessive platelet disorder with giant platelets, thrombocytopenia, and prolonged bleeding time. GPIb is critical for platelet adhesion to damaged vascular wall via vWF. Compare with Glanzmann thrombasthenia (GPIIb/IIIa defect — platelet aggregation defect).',3,'apply',['Bernard-Soulier','GPIb','platelet-adhesion','vWF','giant-platelets']);
add('hem-coag','What are D-dimers and what is their clinical utility in diagnosing VTE?','Fibrin degradation products elevated in VTE, PE, DIC, and many other conditions; high sensitivity (~95%) but low specificity — useful for ruling OUT VTE when pre-test probability is low','D-dimers should only be ordered when pre-test probability is low (Wells score ≤1 for DVT, ≤4 for PE). A negative D-dimer effectively rules out VTE. Positive D-dimer requires imaging (ultrasound for DVT, CTPA for PE). Do not order with high pre-test probability.',3,'apply',['D-dimer','VTE','sensitivity','Wells-score','CTPA']);

// hem-lymphoma (10)
add('hem-lymphoma','What is the most common presenting symptom of Hodgkin lymphoma (HL)?','Painless cervical or supraclavicular lymphadenopathy','HL affects young adults (bimodal: 15–35 and >55 years) and presents with painless lymphadenopathy in cervical/mediastinal region. B symptoms (fever >38°C, night sweats, >10% weight loss) are adverse prognostic factors. Reed-Sternberg cells are pathognomonic.',2,'recall',['Hodgkin-lymphoma','lymphadenopathy','Reed-Sternberg','B-symptoms','prognosis']);
add('hem-lymphoma','What is the Ann Arbor staging system for lymphoma?','Stage I: one lymph node region; II: two or more regions same side of diaphragm; III: both sides; IV: extranodal dissemination; A=no B symptoms, B=B symptoms present','Ann Arbor staging guides treatment intensity. For HL, stages I-II are early disease (curable with combined chemo-RT); stages III-IV require ABVD chemotherapy (doxorubicin, bleomycin, vinblastine, dacarbazine) × 6 cycles.',2,'recall',['Ann-Arbor-staging','lymphoma','Hodgkin','staging','ABVD']);
add('hem-lymphoma','What distinguishes diffuse large B-cell lymphoma (DLBCL) from follicular lymphoma?','DLBCL is aggressive (grows rapidly, often symptomatic) and potentially curable; follicular lymphoma is indolent (slow-growing, often asymptomatic) but generally incurable with conventional therapy','DLBCL is the most common NHL. Treatment: R-CHOP (rituximab, cyclophosphamide, doxorubicin, vincristine, prednisone) × 6 cycles. Follicular lymphoma: watch-and-wait if asymptomatic, rituximab-based therapy when treatment indicated.',3,'apply',['DLBCL','follicular-lymphoma','NHL','R-CHOP','rituximab']);
add('hem-lymphoma','What is the mechanism of action of rituximab in lymphoma treatment?','Anti-CD20 monoclonal antibody that causes complement-dependent cytotoxicity, ADCC, and direct apoptosis of B cells','CD20 is expressed on mature B cells and >90% of B-cell NHLs. Rituximab + chemotherapy (R-CHOP) is standard for most B-cell lymphomas. Side effects: infusion reactions, hepatitis B reactivation (must screen all patients before rituximab).',3,'apply',['rituximab','CD20','B-cell-lymphoma','mechanism','R-CHOP']);
add('hem-lymphoma','A 65-year-old man with CLL develops autoimmune hemolytic anemia. What is the treatment?','Corticosteroids (prednisone) ± rituximab for AIHA; CLL treatment with ibrutinib or venetoclax if CLL itself requires therapy','AIHA complicates 10–25% of CLL. Warm AIHA responds to steroids. Rituximab is effective for steroid-refractory cases. Avoid fludarabine in CLL patients with AIHA as it can worsen it.',3,'apply',['CLL','autoimmune-hemolytic-anemia','prednisone','rituximab','ibrutinib']);
add('hem-lymphoma','What is the recommended initial workup for newly diagnosed lymphoma?','Excisional lymph node biopsy (not FNA), CT chest/abdomen/pelvis, PET scan for staging, bone marrow biopsy (for NHL), CBC, LDH, uric acid, hepatitis B/C serology, HIV','FNA is insufficient for lymphoma subtyping — architectural pattern assessment requires excisional or core needle biopsy. PET-CT is standard for HL and DLBCL staging. LDH is a prognostic marker in NHL.',3,'apply',['lymphoma-workup','excisional-biopsy','PET-CT','staging','LDH']);
add('hem-lymphoma','What is the International Prognostic Index (IPI) used for in lymphoma?','Predicting prognosis in aggressive NHL (DLBCL); risk factors: age >60, elevated LDH, ECOG PS >1, Stage III/IV, >1 extranodal site','IPI scores 0–5: low (0–1), low-intermediate (2), high-intermediate (3), high (4–5) risk. 5-year OS ranges from ~70% (low) to ~30% (high). Adapted R-IPI is used in rituximab era.',3,'apply',['IPI','DLBCL','prognosis','NHL','R-IPI']);
add('hem-lymphoma','What is the cure rate for early-stage (Stage I-II) classical Hodgkin lymphoma with combined modality therapy?','>90% cure rate with ABVD chemotherapy + involved-field radiation therapy','HL is one of the most curable cancers. Long-term survivorship issues include secondary malignancies (breast cancer in women irradiated for mediastinal disease), cardiac disease, pulmonary toxicity (bleomycin), and infertility.',2,'recall',['Hodgkin-lymphoma','cure-rate','ABVD','combined-modality','survivorship']);
add('hem-lymphoma','A patient on long-term immunosuppression post-renal transplant develops lymphadenopathy and B symptoms. Biopsy shows EBV-positive large B-cell proliferation. What is the diagnosis?','Post-transplant lymphoproliferative disorder (PTLD)','PTLD occurs in 1–3% of solid organ transplants, driven by EBV-positive B-cell proliferation in the setting of impaired T-cell immunity. First step: reduce immunosuppression. Rituximab for CD20+ PTLD. Chemotherapy for aggressive forms.',3,'apply',['PTLD','post-transplant','EBV','immunosuppression','rituximab']);
add('hem-lymphoma','Which lymphoma subtype is strongly associated with H. pylori infection?','Gastric MALT lymphoma (mucosa-associated lymphoid tissue lymphoma)','H. pylori-driven chronic antigenic stimulation leads to gastric MALT lymphoma. Eradication of H. pylori with triple therapy results in regression of early-stage gastric MALT in 70–80% of cases. H. pylori eradication is first-line therapy.',2,'recall',['MALT-lymphoma','H-pylori','gastric','eradication','B-cell-lymphoma']);

// ent-ear (7)
add('ent-ear','What is the most common causative organism of acute otitis media in children?','Streptococcus pneumoniae (most common), followed by non-typeable Haemophilus influenzae and Moraxella catarrhalis','AOM is most common in children 6–24 months. Pneumococcal conjugate vaccine (PCV13/PCV15) has reduced S. pneumoniae AOM. First-line treatment: amoxicillin 90 mg/kg/day divided BID for 10 days (high-dose to overcome resistance).',2,'recall',['acute-otitis-media','Streptococcus-pneumoniae','amoxicillin','children','PCV13']);
add('ent-ear','What is the Rinne test and what result indicates conductive hearing loss?','Rinne test compares air conduction (AC) vs. bone conduction (BC) using a tuning fork; negative Rinne (BC > AC) indicates conductive hearing loss','Normal/sensorineural hearing loss: AC > BC (positive Rinne). Conductive hearing loss: BC > AC (negative Rinne) because air conduction is blocked (effusion, ossicular disease, EAC obstruction). Weber test localizes to affected ear in conductive loss.',2,'recall',['Rinne-test','hearing-loss','conductive','bone-conduction','tuning-fork']);
add('ent-ear','What is Menière disease and what is its classic tetrad of symptoms?','Endolymphatic hydrops of the inner ear; tetrad: episodic vertigo (>20 min), fluctuating sensorineural hearing loss, tinnitus, and aural fullness','Menière disease is diagnosed clinically. Treatment: low-sodium diet, diuretics (hydrochlorothiazide + triamterene), vestibular suppressants (dimenhydrinate) for acute attacks. Intratympanic gentamicin or endolymphatic sac decompression for refractory cases.',3,'apply',['Meniere-disease','endolymphatic-hydrops','vertigo','sensorineural-hearing-loss','tinnitus']);
add('ent-ear','What is benign paroxysmal positional vertigo (BPPV) and what is the first-line treatment?','Canalith displacement into semicircular canal causing brief positional vertigo; first-line: Epley maneuver (canalith repositioning)','BPPV is the most common cause of vertigo. Dix-Hallpike test reproduces posterior canal BPPV. Epley maneuver cures 80–90%. No medication needed. Semont maneuver is an alternative. Recurrence rate is 15–50% within 1 year.',2,'recall',['BPPV','canalith','Epley-maneuver','Dix-Hallpike','vertigo']);
add('ent-ear','A 5-year-old with recurrent AOM (>3 per 6 months) and bilateral effusions for >3 months with 30 dB hearing loss is referred for what procedure?','Tympanostomy tube insertion (ventilation tubes / grommets)','Indications for tubes: recurrent AOM ≥3 in 6 months or ≥4 in 12 months; OME >3 months with hearing loss ≥25 dB; OME with speech delay or learning problems. Tubes equalize middle ear pressure and drain effusions.',2,'recall',['tympanostomy-tube','otitis-media','ventilation-tube','grommet','hearing-loss']);
add('ent-ear','What is otosclerosis and what are the audiological findings?','Abnormal remodeling of the otic capsule causing fixation of the stapes footplate; findings: progressive conductive hearing loss with Carhart notch (reduced bone conduction at 2000 Hz) and normal TM on otoscopy','Otosclerosis is autosomal dominant, common in white women, worsened by pregnancy. Audiogram: conductive hearing loss with Carhart notch at 2000 Hz, absent stapedial reflexes, type As (low compliance) tympanogram. Treatment: stapedotomy/stapedectomy.',3,'apply',['otosclerosis','Carhart-notch','stapedotomy','conductive-hearing-loss','stapes']);
add('ent-ear','What is the most appropriate management of a single episode of sudden sensorineural hearing loss?','Urgent ENT referral + oral corticosteroids (prednisone 1 mg/kg/day × 7–14 days) within 72 hours','Sudden SNHL (≥30 dB loss over ≥3 frequencies within 72 h) may be idiopathic, viral, or vascular. High-dose corticosteroids improve recovery. MRI brain/IAC to exclude acoustic neuroma. Hyperbaric oxygen is adjunctive in some centers.',3,'apply',['sudden-sensorineural-hearing-loss','prednisone','ENT-referral','MRI','acoustic-neuroma']);

// ent-urg (7)
add('ent-urg','A 3-year-old child is brought to the ED with sudden-onset stridor at rest, drooling, and a muffled "hot potato" voice. He appears toxic and is sitting upright. What is the immediate priority?','Maintain airway; do NOT examine the throat or lay the child down — emergent anesthesia/ENT for intubation in OR','This presentation is epiglottitis until proven otherwise (H. influenzae type b or S. aureus). Manipulating the throat can trigger complete airway obstruction. Call anesthesia and ENT immediately. After airway secured: ceftriaxone IV, dexamethasone.',5,'analyze',['epiglottitis','stridor','airway-emergency','H-influenzae','ceftriaxone']);
add('ent-urg','What is the most common complication of untreated group A streptococcal pharyngitis?','Peritonsillar abscess (PTA) — collection of pus between the tonsil and superior constrictor muscle','PTA presents with unilateral bulging of the soft palate, uvular deviation, severe dysphagia, trismus, and "hot potato" voice. Treatment: needle aspiration or I&D + penicillin IV, then PO amoxicillin-clavulanate. Quinsy tonsillectomy for recurrent PTA.',3,'apply',['peritonsillar-abscess','group-A-strep','pharyngitis','uvular-deviation','trismus']);
add('ent-urg','An adult presents with 3 days of right-sided facial pain, purulent nasal discharge, fever, and maxillary teeth pain worse on leaning forward. What is the diagnosis and treatment?','Acute bacterial rhinosinusitis (ABRS); treat with amoxicillin 500 mg TID × 10 days if moderate-severe or no improvement after 7 days of symptomatic therapy','ABRS requires: symptoms >10 days without improvement, or severe symptoms (fever >39°C, unilateral facial pain) from onset, or double-worsening. Most viral ARS resolves in 7–10 days. Saline irrigation and decongestants provide symptomatic relief.',3,'apply',['acute-sinusitis','ABRS','amoxicillin','facial-pain','rhinosinusitis']);
add('ent-urg','What are the danger signs of orbital cellulitis (vs periorbital/preseptal cellulitis)?','Proptosis, ophthalmoplegia (restricted/painful eye movements), diplopia, decreased visual acuity, and afferent pupillary defect — all indicate postseptal (orbital) cellulitis','Orbital cellulitis is a surgical emergency requiring CT orbits + sinuses, IV antibiotics (vancomycin + ceftriaxone), and ophthalmology/ENT consultation. Periorbital cellulitis (preseptal) is treated with oral antibiotics.',4,'analyze',['orbital-cellulitis','proptosis','ophthalmoplegia','preseptal','CT-orbits']);
add('ent-urg','What is the management of a posterior epistaxis that fails conservative measures?','Posterior nasal packing (or Foley catheter balloon) + anterior packing; consult ENT for arterial ligation or embolization if packing fails','Posterior epistaxis is from the sphenopalatine artery. It is less common but more dangerous than anterior bleeds (Kiesselbach plexus). Posterior packing requires hospital admission for monitoring (risk of hypoxia, pressure necrosis).',3,'apply',['epistaxis','posterior-nasal-packing','sphenopalatine-artery','ENT','arterial-embolization']);
add('ent-urg','A 45-year-old presents with sudden onset severe unilateral otalgia, vesicles in the ear canal, facial nerve palsy, and vertigo. What is the diagnosis?','Ramsay Hunt syndrome (herpes zoster oticus — reactivation of VZV in geniculate ganglion)','Triad: otic pain, vesicles in the ear/pinna, and ipsilateral facial palsy. Treatment: oral acyclovir/valacyclovir + prednisone within 72 hours. Prognosis for facial nerve recovery is worse than Bell palsy. Audiometry for SNHL.',3,'apply',['Ramsay-Hunt','herpes-zoster-oticus','facial-palsy','VZV','valacyclovir']);
add('ent-urg','What is the appropriate management of a fish bone foreign body in the pharynx/esophagus?','Direct or indirect laryngoscopy ± rigid esophagoscopy under GA for retrieval if lodged below cricopharyngeus','Fish bones are radiopaque on lateral neck X-ray but are often missed. Bones above the cricopharyngeus can be removed in the ED with forceps. Bones in the esophagus require rigid endoscopy. Flexible endoscopy is second choice. CT neck/chest if X-ray negative but high suspicion.',3,'apply',['foreign-body','pharynx','esophagoscopy','fish-bone','laryngoscopy']);

// ophtho-urg (7)
add('ophtho-urg','A 68-year-old man suddenly develops unilateral painless loss of vision described as "a curtain coming down." Fundoscopy shows a white, edematous retina with a cherry red spot at the macula. What is the diagnosis?','Central retinal artery occlusion (CRAO)','CRAO is an ocular emergency — irreversible ischemic damage occurs within 90–100 minutes. Cherry red spot = preserved choroidal circulation at fovea against pale ischemic background. Management (controversial efficacy): ocular massage, IOP lowering, emergent ophthalmology. Evaluate for cardioembolic source (AF, carotid stenosis).',4,'analyze',['CRAO','central-retinal-artery-occlusion','cherry-red-spot','painless-vision-loss','ocular-emergency']);
add('ophtho-urg','What is the treatment for acute angle-closure glaucoma?','Immediate IOP lowering: IV acetazolamide + topical beta-blocker (timolol) + topical alpha-agonist (apraclonidine) + pilocarpine; definitive: laser peripheral iridotomy','Acute angle-closure presents with severe eye pain, blurred vision, halos around lights, red eye, dilated fixed pupil, corneal edema, and nausea/vomiting. IOP may be >50 mmHg. Avoid mydriatics. Urgent ophthalmology consult.',4,'analyze',['acute-angle-closure-glaucoma','IOP','acetazolamide','pilocarpine','laser-iridotomy']);
add('ophtho-urg','A 25-year-old contact lens wearer presents with a painful red eye, photophobia, and a white corneal infiltrate. What is the diagnosis and emergency management?','Bacterial (or Acanthamoeba) keratitis; stop contact lens use, urgent ophthalmology consult, topical fluoroquinolone (ciprofloxacin or ofloxacin drops hourly)','Corneal ulcer in a contact lens wearer is an ocular emergency. Pseudomonas is common in contact lens-associated keratitis. Acanthamoeba should be suspected in pool water/tap water exposure. Corneal scraping for culture before antibiotics.',4,'analyze',['keratitis','corneal-ulcer','contact-lens','Pseudomonas','fluoroquinolone']);
add('ophtho-urg','A 70-year-old diabetic patient with proliferative retinopathy develops sudden painless dense vision loss with inability to see fundus on examination. What is the most likely cause?','Vitreous hemorrhage from neovascularization rupture','Vitreous hemorrhage obscures the view of the fundus ("black eye" view). Urgent B-scan ultrasound confirms diagnosis and rules out retinal detachment. Treatment: observation (often clears spontaneously), or vitrectomy if persistent. Panretinal photocoagulation to treat underlying neovascularization.',3,'apply',['vitreous-hemorrhage','diabetic-retinopathy','neovascularization','vitrectomy','panretinal-photocoagulation']);
add('ophtho-urg','What are the signs of a ruptured globe and what is the immediate management?','Hypotony, peaked/teardrop pupil, chemosis, subconjunctival hemorrhage 360°, uveal prolapse; management: rigid eye shield, NPO, IV antibiotics, emergent ophthalmology for repair','Never apply pressure to a suspected ruptured globe — can expulse intraocular contents. Give tetanus prophylaxis, IV cefazolin + gentamicin (or ciprofloxacin). CT orbits (not MRI if metallic FB suspected). OR within hours.',5,'analyze',['ruptured-globe','ocular-trauma','teardrop-pupil','eye-shield','emergency-surgery']);
add('ophtho-urg','What is the classic presentation of giant cell arteritis (temporal arteritis) and what is the immediate management to prevent vision loss?','Age >50, temporal headache, jaw claudication, scalp tenderness; ESR >50; immediate high-dose prednisone 1 mg/kg/day (60 mg) before biopsy','GCA can cause ischemic optic neuropathy leading to permanent blindness. If visual symptoms are present, use IV methylprednisolone 500–1000 mg/day × 3 days. Temporal artery biopsy within 2 weeks (steroids do not negate biopsy findings within 2 weeks).',4,'analyze',['giant-cell-arteritis','temporal-arteritis','vision-loss','prednisone','temporal-artery-biopsy']);
add('ophtho-urg','What is a relative afferent pupillary defect (RAPD) and what does it indicate?','Asymmetric pupillary light reflex: when light is swung to affected eye, both pupils dilate instead of constricting (Marcus Gunn pupil); indicates optic nerve or severe retinal disease in that eye','RAPD is detected by the swinging flashlight test. It indicates unilateral or asymmetric bilateral optic nerve disease (optic neuritis, CRAO, severe glaucoma). A normal RAPD rules out significant afferent pathway damage on the examined side.',3,'apply',['RAPD','afferent-pupillary-defect','Marcus-Gunn','optic-neuritis','swinging-flashlight']);

// uro-uti (10)
add('uro-uti','What is the definition of asymptomatic bacteriuria (ASB) and in which populations should it be treated?','≥10⁵ CFU/mL in one (women) or two (men) clean-catch midstream specimens without UTI symptoms; treat only in pregnant women and before urological procedures','IDSA/AMMI guidelines: routine treatment of ASB in elderly, diabetics, catheterized patients, or before non-urological surgery is not recommended and increases antibiotic resistance. Screen and treat in pregnancy (risk of pyelonephritis and preterm birth).',3,'apply',['asymptomatic-bacteriuria','ASB','pregnancy','treatment-guidelines','AMMI']);
add('uro-uti','A 25-year-old non-pregnant woman presents with 2 days of dysuria, frequency, and urgency without fever or flank pain. Urinalysis shows pyuria and bacteriuria. What is first-line treatment?','Nitrofurantoin macrocrystals 100 mg BID × 5 days, or trimethoprim-sulfamethoxazole 160/800 mg BID × 3 days (if local resistance <20%), or fosfomycin 3 g single dose','Uncomplicated UTI in premenopausal non-pregnant women. Fluoroquinolones should be reserved for more serious infections to preserve effectiveness. Check local antibiogram for TMP-SMX resistance rates.',2,'recall',['uncomplicated-UTI','nitrofurantoin','TMP-SMX','fosfomycin','cystitis']);
add('uro-uti','What clinical and laboratory features distinguish uncomplicated cystitis from pyelonephritis?','Pyelonephritis: fever >38°C, rigors, costovertebral angle tenderness/pain, nausea/vomiting, elevated WBC and CRP — cystitis lacks these systemic features','Distinction matters because pyelonephritis requires longer antibiotic course (7–14 days) and may require IV antibiotics if severe. Blood cultures if systemically ill. Imaging (CT/US) if no improvement at 48–72 hours.',3,'apply',['pyelonephritis','cystitis','CVA-tenderness','fever','clinical-differentiation']);
add('uro-uti','What is the antibiotic of choice for acute uncomplicated pyelonephritis in an outpatient?','Ciprofloxacin 500 mg BID × 7 days (if susceptible) or TMP-SMX 160/800 mg BID × 14 days','Fluoroquinolones are first-line for pyelonephritis because they achieve high urinary and tissue concentrations. Beta-lactams are less effective for pyelonephritis. If local fluoroquinolone resistance >10%, obtain culture and use based on susceptibility.',3,'apply',['pyelonephritis','ciprofloxacin','outpatient','fluoroquinolone','antibiotic-treatment']);
add('uro-uti','What is the most common organism causing UTI overall?','Escherichia coli (accounts for 75–90% of community-acquired uncomplicated UTIs)','E. coli produces fimbriae (type 1 and P) that allow adhesion to uroepithelium. Other common organisms: Klebsiella pneumoniae, S. saprophyticus (young women), Proteus mirabilis (struvite stones), Enterococcus faecalis.',1,'recall',['E-coli','UTI','uropathogens','fimbriae','microbiology']);
add('uro-uti','A 75-year-old man with a Foley catheter develops fever, rigors, and pyuria. Urine culture grows >10⁵ CFU/mL of P. aeruginosa. What is the management?','Remove or replace catheter, treat with anti-pseudomonal antibiotic (piperacillin-tazobactam or cefepime or ciprofloxacin based on sensitivity) for 7 days','Catheter-associated UTI (CAUTI): catheter removal is the most important intervention. Use smallest bore catheter for shortest time. Pseudomonas is an intrinsically resistant organism — susceptibility testing is essential. Prevention: bladder bundles, closed drainage systems.',4,'analyze',['CAUTI','catheter-UTI','Pseudomonas','piperacillin-tazobactam','catheter-removal']);
add('uro-uti','What is recurrent UTI and what prophylactic strategies are available for women?','≥2 UTIs in 6 months or ≥3 in 12 months; strategies: post-coital antibiotic prophylaxis, continuous low-dose prophylaxis (nitrofurantoin or TMP), patient-initiated therapy, cranberry products (modest evidence)','Recurrent UTIs affect 25% of women after first episode. Topical estrogen for postmenopausal women reduces recurrences by restoring vaginal lactobacillus colonization. Cranberry (proanthocyanidins) may prevent E. coli adhesion.',3,'apply',['recurrent-UTI','prophylaxis','nitrofurantoin','post-coital','cranberry']);
add('uro-uti','What is the appropriate investigation for a man with his first UTI?','Urine culture, urinalysis; consider urology referral and renal/bladder ultrasound to exclude structural abnormality or obstruction','UTIs in men are considered complicated. Causes include prostatitis, BPH, urethral stricture, or calculi. Blood cultures if febrile. Treat for 7–14 days (vs. 3 days for women). Ciprofloxacin or TMP-SMX depending on culture.',3,'apply',['male-UTI','complicated-UTI','prostatitis','urological-workup','urology-referral']);
add('uro-uti','What is the CAUTI prevention bundle per Safer Healthcare Now!/IPAC Canada?','Appropriate catheter indication, insertion using aseptic technique, closed drainage system maintenance, daily assessment for removal (ABCDE bundle), and nurse-driven protocol for early catheter removal','Catheter-associated UTIs are the most common healthcare-associated infections. Every day with an unnecessary catheter increases CAUTI risk by 3–7%. Regular reassessment of catheter necessity is the most impactful intervention.',3,'apply',['CAUTI-prevention','catheter-bundle','IPAC','healthcare-associated-infection','aseptic-technique']);
add('uro-uti','What is urethritis and which organisms cause it in sexually active young adults?','Inflammation of the urethra caused by STIs; most common: Chlamydia trachomatis (non-gonococcal urethritis) and Neisseria gonorrhoeae','Symptoms: dysuria, urethral discharge, meatal erythema. NAAT (urine or urethral swab) for gonorrhea and chlamydia. Treat empirically for both: ceftriaxone 500 mg IM (gonorrhea) + azithromycin 1 g PO or doxycycline 100 mg BID × 7 days (chlamydia). Notify and treat partners.',3,'apply',['urethritis','chlamydia','gonorrhea','NAAT','ceftriaxone']);

// uro-prostate (10)
add('uro-prostate','What is benign prostatic hyperplasia (BPH) and what are the typical lower urinary tract symptoms (LUTS)?','Non-malignant enlargement of the prostate causing bladder outlet obstruction; LUTS: urinary frequency, urgency, nocturia (storage symptoms), weak stream, hesitancy, straining, incomplete emptying (voiding symptoms)','BPH affects >50% of men >60 years. IPSS (International Prostate Symptom Score) quantifies severity. DRE: smooth, rubbery enlargement. First-line treatment: lifestyle modifications, then alpha-blockers (tamsulosin) or 5-alpha-reductase inhibitors (finasteride).',2,'recall',['BPH','LUTS','tamsulosin','finasteride','IPSS']);
add('uro-prostate','What is the mechanism of action of alpha-1 blockers (tamsulosin, alfuzosin) in treating BPH?','Relax smooth muscle in prostate and bladder neck by blocking alpha-1 adrenergic receptors, reducing outlet resistance','Alpha-1 blockers provide faster symptom relief (1–2 weeks) than 5-ARIs. Side effects: orthostatic hypotension, retrograde ejaculation, rhinitis. Tamsulosin is more uroselective with fewer systemic effects than terazosin/doxazosin.',2,'recall',['alpha-blocker','tamsulosin','BPH','mechanism','alpha-1-adrenergic']);
add('uro-prostate','A 70-year-old man with BPH cannot void and has a palpable bladder. What is the acute management?','Urinary catheterization (Foley catheter) to relieve acute urinary retention','Acute urinary retention is a urological emergency. Post-void residual on ultrasound or catheterization >300 mL confirms significant retention. Start alpha-blocker before catheter removal (trial without catheter in 24–72 h). Urology referral for TURP if recurrent or fails trial.',3,'apply',['acute-urinary-retention','catheterization','BPH','alpha-blocker','TURP']);
add('uro-prostate','What PSA level and DRE finding warrant urology referral for possible prostate cancer in a 55-year-old man?','PSA >3–4 ng/mL or abnormal DRE (firm, irregular, asymmetric nodule or induration) regardless of PSA','Canadian Cancer Society: offer PSA screening discussion to men 50–74 (or 40+ with risk factors: African ancestry, family history). Abnormal DRE + any PSA, or PSA >3–4 → transrectal ultrasound-guided biopsy or MRI-targeted biopsy.',3,'apply',['PSA','prostate-cancer','DRE','urology-referral','screening']);
add('uro-prostate','What is the gleason grading system for prostate cancer?','Histological grading based on differentiation; Gleason grade 1–5 (most to least differentiated); combined Gleason score (primary + secondary pattern) 6–10; Grade group 1–5 maps to Gleason scores 6, 3+4=7, 4+3=7, 8, 9–10','Gleason ≤6 (Grade group 1) = low-risk, favorable prognosis. Gleason ≥8 (Grade group 4–5) = high-risk, aggressive. The Grade Group system (1–5) is now preferred for clarity. Used in risk stratification and treatment decisions.',2,'recall',['Gleason-score','prostate-cancer','grade-group','risk-stratification','histology']);
add('uro-prostate','What is active surveillance in prostate cancer and when is it appropriate?','Regular monitoring (PSA every 3–6 months, DRE, repeat biopsy ±MRI) without immediate treatment; appropriate for low-risk, localized prostate cancer (Gleason 6, PSA <10, T1c-T2a, <3 cores positive)','Active surveillance avoids overtreatment of indolent cancers. Approximately 30% of patients on AS will eventually require treatment (progression). It is endorsed by the Canadian Urological Association (CUA) for Grade Group 1 disease.',3,'apply',['active-surveillance','prostate-cancer','low-risk','CUA','Gleason-6']);
add('uro-prostate','What are the most common side effects of radical prostatectomy vs. external beam radiotherapy for prostate cancer?','Prostatectomy: erectile dysfunction (~60–80%) and urinary incontinence (5–15%); radiotherapy: rectal toxicity (bleeding, urgency), cystitis, and later development of ED','Both are equivalent in cancer control for localized disease. Choice depends on patient preference, anatomy, comorbidities, and urinary/sexual function baseline. Brachytherapy and HIFU are alternatives for appropriate candidates.',3,'apply',['prostate-cancer','prostatectomy','radiotherapy','erectile-dysfunction','side-effects']);
add('uro-prostate','What is the first-line treatment for metastatic castration-sensitive prostate cancer (mCSPC)?','Androgen deprivation therapy (ADT) + docetaxel or abiraterone acetate (intensification therapy)','ADT alone (surgical or medical castration with LHRH agonist/antagonist) is no longer standard for mCSPC. Intensification with docetaxel (CHAARTED trial) or abiraterone (LATITUDE trial) significantly improves overall survival.',3,'apply',['prostate-cancer','ADT','metastatic','abiraterone','docetaxel']);
add('uro-prostate','A 65-year-old man on long-term ADT for prostate cancer develops osteoporosis. What should be prescribed?','Calcium + vitamin D + bisphosphonate (zoledronic acid annually) or denosumab','ADT causes castrate testosterone levels → bone loss and increased fracture risk. DEXA scan should be performed at baseline and every 1–2 years. Zoledronic acid or denosumab reduce fracture risk. Prevent falls (exercise, medication review).',3,'apply',['ADT','osteoporosis','prostate-cancer','zoledronic-acid','denosumab']);
add('uro-prostate','What is the purpose of the IPSS (International Prostate Symptom Score) in BPH management?','Quantifies symptom severity: 0–7 mild, 8–19 moderate, 20–35 severe; guides treatment decisions','IPSS includes 7 voiding/storage symptom questions plus quality-of-life item. Mild symptoms (≤7): watchful waiting. Moderate (8–19): medical therapy. Severe (≥20) or failed medical therapy: surgical intervention (TURP, laser prostatectomy).',2,'recall',['IPSS','BPH','symptom-score','TURP','treatment-decision']);

// pharm-antimicrobials (15)
add('pharm-antimicrobials','What is the mechanism of action of beta-lactam antibiotics?','Inhibit bacterial cell wall synthesis by binding to penicillin-binding proteins (PBPs), blocking transpeptidation of peptidoglycan cross-links → cell lysis','Beta-lactams (penicillins, cephalosporins, carbapenems, monobactams) are bactericidal. Resistance mechanisms: beta-lactamase production (cleaves beta-lactam ring), altered PBPs (MRSA), and porins changes (gram-negatives).',2,'recall',['beta-lactam','mechanism','PBP','peptidoglycan','bactericidal']);
add('pharm-antimicrobials','A patient with a penicillin allergy labelled as "anaphylaxis" requires antibiotic treatment for a serious gram-positive infection. What is the safest alternative?','Vancomycin (for gram-positive infections) or aztreonam (for gram-negative coverage if needed)','Cross-reactivity between penicillin and cephalosporins: ~1–2% (much lower than previously thought, only with same R1 side chain). For true penicillin anaphylaxis: avoid all beta-lactams; use vancomycin, clindamycin, or TMP-SMX depending on indication. Penicillin allergy delabeling should be performed when feasible.',3,'apply',['penicillin-allergy','cross-reactivity','vancomycin','aztreonam','allergy-delabeling']);
add('pharm-antimicrobials','What class of antibiotics inhibits protein synthesis by binding to the 30S ribosomal subunit and what are their major side effects?','Aminoglycosides (gentamicin, tobramycin, amikacin); major side effects: nephrotoxicity and ototoxicity (cochlear and vestibular)','Aminoglycosides are bactericidal. Once-daily dosing reduces nephrotoxicity. Drug levels (trough) must be monitored. Contraindicated in myasthenia gravis (neuromuscular blockade) and pregnancy (congenital deafness). Synergistic with beta-lactams for enterococcal endocarditis.',2,'recall',['aminoglycoside','30S-ribosome','nephrotoxicity','ototoxicity','gentamicin']);
add('pharm-antimicrobials','What is the mechanism of macrolide resistance and which macrolide has the fewest drug interactions?','Macrolide resistance: methylation of 23S rRNA (erm genes), efflux pumps (mef genes); azithromycin has fewer drug interactions than clarithromycin (which is a strong CYP3A4 inhibitor)','Macrolides (azithromycin, clarithromycin, erythromycin) inhibit 50S ribosome. Erythromycin causes GI side effects and multiple drug interactions. Azithromycin has a long tissue half-life (3 days) allowing Z-pack regimens. Use with caution in QTc prolongation.',3,'apply',['macrolide','resistance','CYP3A4','azithromycin','clarithromycin']);
add('pharm-antimicrobials','What is the clinical indication for metronidazole and why must alcohol be strictly avoided?','Metronidazole: anaerobic bacteria and protozoal infections (C. difficile, Trichomonas, Giardia, amoebiasis, BV); inhibits aldehyde dehydrogenase → disulfiram-like reaction with alcohol (flushing, nausea, vomiting, headache)','Metronidazole is the drug of choice for mild-moderate C. difficile and BV. Avoid with alcohol during treatment and 48 hours after last dose. Side effects: metallic taste, peripheral neuropathy (with prolonged use).',2,'recall',['metronidazole','anaerobes','disulfiram-reaction','alcohol','C-difficile']);
add('pharm-antimicrobials','What is the mechanism of fluoroquinolone resistance and which fluoroquinolone is approved for community-acquired pneumonia (CAP)?','Resistance: mutations in DNA gyrase (gyrA) and topoisomerase IV (parC); levofloxacin and moxifloxacin are "respiratory fluoroquinolones" approved for CAP with atypical and S. pneumoniae coverage','Fluoroquinolones inhibit DNA gyrase and topoisomerase IV. Ciprofloxacin lacks adequate S. pneumoniae coverage. Fluoroquinolones prolong QTc, cause tendinopathy (especially Achilles), peripheral neuropathy, and are associated with C. difficile. Avoid in pregnancy and children.',3,'apply',['fluoroquinolone','levofloxacin','CAP','gyrA','QTc-prolongation']);
add('pharm-antimicrobials','What is the first-line treatment for MRSA bacteremia?','Vancomycin IV (target trough 15–20 mg/L or AUC/MIC 400–600) or daptomycin 6–8 mg/kg IV daily','MRSA bacteremia requires bactericidal therapy for minimum 14 days (uncomplicated) or 4–6 weeks (endocarditis, metastatic infection). Source control (catheter removal, debridement) is essential. IDSA 2022 prefers AUC-guided vancomycin dosing.',3,'apply',['MRSA','vancomycin','daptomycin','bacteremia','AUC-guided-dosing']);
add('pharm-antimicrobials','What antibiotic is used for prophylaxis against Pneumocystis jirovecii pneumonia (PJP) in immunocompromised patients?','Trimethoprim-sulfamethoxazole (TMP-SMX) 1 DS tablet daily or 3×/week','PJP prophylaxis is indicated when CD4 count <200 cells/µL (HIV), high-dose steroids (>20 mg/day for >1 month), hematological malignancy, or solid organ transplant. Alternative if TMP-SMX intolerant: dapsone, atovaquone, or pentamidine inhaler.',2,'recall',['PJP-prophylaxis','TMP-SMX','immunocompromised','CD4','dapsone']);
add('pharm-antimicrobials','What is the mechanism of action of vancomycin?','Inhibits bacterial cell wall synthesis by binding to D-Ala-D-Ala terminus of peptidoglycan precursors, blocking transglycosylation and transpeptidation','Vancomycin is bactericidal against gram-positive organisms but does not penetrate gram-negative outer membrane. VRE (vancomycin-resistant enterococci) have modified D-Ala-D-Lac (vanA/vanB genes). Infusion-related "Red Man Syndrome" is rate-dependent, not true allergy.',2,'recall',['vancomycin','mechanism','D-Ala-D-Ala','VRE','Red-Man-Syndrome']);
add('pharm-antimicrobials','What is carbapenem-resistant Enterobacteriaceae (CRE) and why is it clinically important?','Gram-negative bacilli resistant to carbapenems (last-resort antibiotics) via KPC, NDM, OXA, or VIM carbapenemases; associated with >50% mortality in bloodstream infections','CRE are pan-resistant or nearly pan-resistant organisms. Treatment options: ceftazidime-avibactam (for KPC), meropenem-vaborbactam, cefiderocol, colistin (last resort). Contact precautions and enhanced infection control are essential.',3,'apply',['CRE','carbapenem-resistance','KPC','ceftazidime-avibactam','antimicrobial-resistance']);
add('pharm-antimicrobials','Which antibiotic class is associated with tendon rupture and how should patients be counseled?','Fluoroquinolones (ciprofloxacin, levofloxacin); counsel patients to stop the drug and seek care if they develop tendon pain or swelling, especially Achilles tendon','Fluoroquinolone tendinopathy: 3–4x increased risk of Achilles tendon rupture. Risk factors: age >60, concomitant corticosteroids, renal failure, prior tendon disease. Health Canada black box warning. Also associated with peripheral neuropathy and aortic aneurysm.',3,'apply',['fluoroquinolone','tendon-rupture','Achilles','corticosteroid','black-box-warning']);
add('pharm-antimicrobials','What is antibiotic stewardship and what are its core principles?','Coordinated interventions to improve antibiotic use, minimize resistance, and reduce adverse effects: use narrowest-spectrum effective agent, shortest effective duration, route conversion PO when possible, de-escalation based on cultures','Antibiotic stewardship programs (ASPs) are mandated in Canadian hospitals. Key tools: prospective audit and feedback, prior authorization, clinical pathways. Reduces C. difficile rates, VRE/MRSA rates, and costs.',2,'recall',['antibiotic-stewardship','ASP','de-escalation','antimicrobial-resistance','C-difficile']);
add('pharm-antimicrobials','What is the appropriate duration of antibiotic treatment for uncomplicated community-acquired pneumonia in a hospitalized patient?','5 days if clinically stable (temperature <37.8°C, HR <100, RR <24, SpO2 >90%, tolerating PO) — shorter courses are equivalent to longer courses','IDSA/ATS CAP guidelines: minimum 5 days; discontinue when afebrile ×48–72 h and ≤1 abnormal vital sign. Procalcitonin-guided therapy reduces duration. Short courses reduce C. difficile, side effects, and antibiotic resistance.',3,'apply',['CAP','antibiotic-duration','stewardship','procalcitonin','IDSA-guidelines']);
add('pharm-antimicrobials','Which antibiotic class is contraindicated in pregnancy due to risk of grey baby syndrome?','Chloramphenicol (inhibits 50S ribosome, used for aplastic anemia-associated cases; neonatal grey baby syndrome from immature glucuronyl transferase leading to drug accumulation)','Grey baby syndrome: cardiovascular collapse, grey skin, hypothermia, abdominal distension in neonates. Chloramphenicol is rarely used today. Tetracyclines (tooth staining, bone growth inhibition) and fluoroquinolones (cartilage toxicity) are also contraindicated in pregnancy.',2,'recall',['chloramphenicol','grey-baby-syndrome','pregnancy','50S-ribosome','antibiotic-contraindication']);
add('pharm-antimicrobials','What antibiotic combination is used for empiric treatment of intra-abdominal infections requiring surgery?','Piperacillin-tazobactam (monotherapy) or cefazolin + metronidazole (for mild-moderate) or meropenem + vancomycin (for severe/healthcare-associated)','Intra-abdominal infections require coverage for gram-negatives (E. coli, Klebsiella) and anaerobes (Bacteroides fragilis). Source control (drainage/resection) is equally important to antibiotics. Duration: 4–7 days post source control.',3,'apply',['intra-abdominal-infection','piperacillin-tazobactam','metronidazole','source-control','peritonitis']);

// pharm-adverse (15)
add('pharm-adverse','A patient on amiodarone develops hypothyroidism 8 months after starting the drug. What is the mechanism?','Amiodarone contains 37% iodine by weight; chronic iodine excess inhibits thyroid hormone synthesis (Wolff-Chaikoff effect) → hypothyroidism (more common); or stimulates excess production → thyrotoxicosis (amiodarone-induced thyroiditis type 2)','Amiodarone-induced thyroid dysfunction (AITD) occurs in 15–20% of patients. Monitor TFTs every 6 months. Hypothyroidism (more common): treat with levothyroxine while continuing amiodarone. Hyperthyroidism: may require amiodarone discontinuation, methimazole, or steroids.',3,'apply',['amiodarone','thyroid','Wolff-Chaikoff','hypothyroidism','adverse-effects']);
add('pharm-adverse','What is serotonin syndrome and which drug combinations most commonly cause it?','Potentially life-threatening condition from excess serotonergic activity: triad of agitation, autonomic instability, and neuromuscular abnormalities (clonus, hyperreflexia, diaphoresis); most common causes: SSRI + MAOI, SSRI + tramadol, SSRI + linezolid','Serotonin syndrome vs. NMS: onset is rapid (hours) with clonus and hyperreflexia (vs. NMS: days, rigidity, bradyreflexia). Treatment: stop offending agents, cyproheptadine (5-HT antagonist), benzodiazepines, supportive care; severe: ICU, intubation.',4,'analyze',['serotonin-syndrome','SSRI','MAOI','clonus','cyproheptadine']);
add('pharm-adverse','What is neuroleptic malignant syndrome (NMS) and how is it treated?','Rare life-threatening reaction to antipsychotics (D2 receptor blockade): hyperthermia, severe muscle rigidity, autonomic instability, altered consciousness; elevated CK; treatment: stop antipsychotic, cooling, dantrolene, bromocriptine, ICU care','NMS is differentiated from serotonin syndrome by its slower onset (days), severe rigidity (lead-pipe), elevated CK (often >1000), and leukocytosis. Risk factors: high-potency typical antipsychotics (haloperidol), rapid dose escalation.',4,'analyze',['NMS','neuroleptic-malignant-syndrome','antipsychotic','dantrolene','bromocriptine']);
add('pharm-adverse','A patient on phenytoin develops nystagmus, ataxia, and confusion. What is the explanation?','Phenytoin toxicity — dose-dependent CNS adverse effects in order of severity: nystagmus (early), ataxia, slurred speech, drowsiness, confusion, coma (severe)','Phenytoin has a narrow therapeutic window (40–80 µmol/L). Non-linear (zero-order) kinetics: small dose increase can cause dramatic level increase. Monitor levels, especially with enzyme inducers/inhibitors. Also watch for gingival hyperplasia, hirsutism, and long-term use causing cerebellar atrophy.',3,'apply',['phenytoin','toxicity','nystagmus','ataxia','narrow-therapeutic-index']);
add('pharm-adverse','Which antihypertensive class is the most common cause of drug-induced cough?','ACE inhibitors (bradykinin-mediated dry cough in 10–15% of patients, higher in Asian patients)','ACEi prevent bradykinin degradation → accumulates in lungs → stimulates cough receptors. Cough is not dose-dependent and resolves within weeks of stopping. Switch to ARB (does not affect bradykinin). ARBs do not cause cough.',2,'recall',['ACE-inhibitor','cough','bradykinin','adverse-effect','ARB']);
add('pharm-adverse','A patient on isoniazid for latent TB develops bilateral foot tingling and burning. What is the cause and treatment?','Peripheral neuropathy due to isoniazid-induced pyridoxine (vitamin B6) deficiency; treat with pyridoxine 25–50 mg/day','INH competes with pyridoxine in pyridoxal phosphate synthesis. Neuropathy risk is higher in slow acetylators, malnutrition, diabetes, and alcohol use. Pyridoxine supplementation is recommended for all patients on INH, especially high-risk groups.',2,'recall',['isoniazid','peripheral-neuropathy','pyridoxine','vitamin-B6','INH']);
add('pharm-adverse','What is the mechanism of statin-induced myopathy and what are the risk factors?','Inhibition of HMG-CoA reductase reduces mevalonate → decreases CoQ10 and farnesyl pyrophosphate → mitochondrial dysfunction in muscle; risk factors: high-dose statins, CYP3A4 inhibitors (e.g., clarithromycin, amiodarone, diltiazem), hypothyroidism, renal/hepatic impairment','CK elevation <10× ULN with symptoms = statin myopathy; >10× ULN = myositis; rhabdomyolysis if CK >10,000 and myoglobinuria. Hydrophilic statins (rosuvastatin, pravastatin) have lower myopathy risk than lipophilic (simvastatin).',3,'apply',['statin-myopathy','rhabdomyolysis','CYP3A4','CK','HMG-CoA']);
add('pharm-adverse','What is QTc prolongation and which common drug classes cause it?','Prolonged QTc (>450 ms men, >470 ms women) increases risk of torsades de pointes (TdP) and sudden cardiac death; common QTc-prolonging drugs: antipsychotics, macrolides (azithromycin, erythromycin), fluoroquinolones (ciprofloxacin), antiarrhythmics (amiodarone, sotalol), methadone, ondansetron','Risk factors for TdP: baseline QTc >500 ms, hypokalemia, hypomagnesemia, bradycardia, congenital LQTS, multiple QTc-prolonging drugs. CredibleMeds (AzCERT) risk stratification database for drug-induced QTc prolongation.',3,'apply',['QTc-prolongation','torsades-de-pointes','antipsychotic','macrolide','fluoroquinolone']);
add('pharm-adverse','A 50-year-old woman taking methotrexate for RA has a significant alcohol intake. Why is this combination especially dangerous?','Both methotrexate and alcohol are hepatotoxic; combined use significantly increases risk of liver fibrosis and cirrhosis','Methotrexate causes hepatic fibrosis, especially with cumulative doses >1.5–3 g. Alcohol >14 units/week is a relative contraindication to MTX therapy. Monitor LFTs every 4–8 weeks; liver biopsy considered if persistent LFT elevation. FibroScan (transient elastography) is a non-invasive alternative.',3,'apply',['methotrexate','alcohol','hepatotoxicity','liver-fibrosis','RA']);
add('pharm-adverse','What is the most serious adverse effect of clozapine that requires mandatory monitoring?','Agranulocytosis (absolute neutrophil count <0.5 × 10⁹/L) — potentially fatal; requires weekly CBC for 6 months, then biweekly, then monthly','Clozapine is the most effective antipsychotic for treatment-resistant schizophrenia but causes agranulocytosis in 0.8–1% of patients. Monitoring protocol: hold clozapine if ANC <1.5 × 10⁹/L; discontinue if <0.5 × 10⁹/L. Also causes myocarditis, metabolic syndrome, and seizures.',3,'apply',['clozapine','agranulocytosis','ANC','CBC-monitoring','treatment-resistant-schizophrenia']);
add('pharm-adverse','A patient on lithium develops coarse tremor, vomiting, diarrhea, and confusion. Lithium level is 2.8 mEq/L. What is the management?','Stop lithium, IV hydration (0.9% NaCl to increase renal clearance), and hemodialysis for severe toxicity (level >2.5 mEq/L with symptoms, or >4 mEq/L regardless of symptoms)','Lithium toxicity triad: GI symptoms + neurological (tremor, ataxia, confusion, seizures) + cardiovascular. Therapeutic range: 0.6–1.2 mEq/L. Toxicity precipitants: NSAIDs, thiazide diuretics, ACEi, dehydration. Narrow therapeutic index requires regular monitoring.',4,'analyze',['lithium-toxicity','hemodialysis','lithium-level','NSAIDs','thiazide']);
add('pharm-adverse','What is drug-induced lupus (DIL) and which medications most commonly cause it?','Drug-induced SLE-like syndrome with anti-histone antibodies; most common drugs: procainamide, hydralazine, isoniazid, minocycline, TNF inhibitors (etanercept, infliximab)','DIL typically resolves within weeks of stopping the drug. Anti-histone antibodies are present in >95% of DIL cases (vs. 70% of idiopathic SLE). Anti-dsDNA is rare in DIL. Symptoms: arthralgia, serositis, rash — renal and CNS involvement rare (unlike idiopathic SLE).',3,'apply',['drug-induced-lupus','anti-histone','procainamide','hydralazine','DIL']);
add('pharm-adverse','What is a Type A vs. Type B adverse drug reaction?','Type A (augmented): predictable, dose-dependent, pharmacologically expected (e.g., hypoglycemia with insulin, bleeding with anticoagulants) — 80% of ADRs; Type B (bizarre): unpredictable, not dose-dependent, often immunological (e.g., penicillin anaphylaxis, SJS)','Type A ADRs are managed by dose reduction or drug switch. Type B (idiosyncratic, immunological) require drug discontinuation. SJS/TEN is an extreme Type B reaction. Causality assessment tools: Naranjo algorithm.',2,'recall',['adverse-drug-reaction','Type-A','Type-B','idiosyncratic','Naranjo']);
add('pharm-adverse','What is Stevens-Johnson syndrome (SJS) and which drugs most commonly cause it?','Severe mucocutaneous blistering reaction with <10% BSA epidermal detachment (SJS) or >30% (TEN); most common drugs: allopurinol, carbamazepine, lamotrigine, sulfonamides, nevirapine, NSAIDs','SJS/TEN: admit to burn unit, stop all suspect drugs, wound care, ophthalmology consult (eye scarring), IV fluids. Cyclosporine and IVIG are used for TEN. Mortality: SJS ~5%, TEN ~30%. HLA-B*1502 (carbamazepine SJS risk in Han Chinese) genetic testing recommended.',4,'analyze',['Stevens-Johnson-syndrome','TEN','SJS','allopurinol','carbamazepine']);
add('pharm-adverse','A patient takes clarithromycin with simvastatin. What adverse drug interaction occurs and why?','Clarithromycin inhibits CYP3A4 → increases simvastatin plasma levels dramatically → severe myopathy and rhabdomyolysis risk','Simvastatin and lovastatin are extensively metabolized by CYP3A4. Co-administration with strong CYP3A4 inhibitors (clarithromycin, itraconazole, HIV PIs, amiodarone, diltiazem, grapefruit) greatly increases statin exposure. Use pravastatin or rosuvastatin (less CYP3A4 dependence) instead.',3,'apply',['clarithromycin','simvastatin','CYP3A4','drug-interaction','rhabdomyolysis']);

